import {
	Scene,
	Mesh,
	PlaneGeometry,
	MeshStandardMaterial,
	MeshBasicMaterial,
	CylinderGeometry,
	LineSegments,
	BufferGeometry,
	LineBasicMaterial,
	Float32BufferAttribute,
	Texture,
	RepeatWrapping,
	SphereGeometry,
	DoubleSide,
	ShaderMaterial,
	BackSide,
	Object3D,
	Box3,
	Vector3,
} from 'three'
import { LineSegments2 } from 'three/examples/jsm/lines/LineSegments2.js'
import { LineSegmentsGeometry } from 'three/examples/jsm/lines/LineSegmentsGeometry.js'
import { LineMaterial } from 'three/examples/jsm/lines/LineMaterial.js'
import type { GLTF } from 'three/examples/jsm/loaders/GLTFLoader.js'
import { FIELD, GOAL_3D } from '../constants'

export interface FieldAssets {
	grassTexture?: Texture | null
	goalGLB?: GLTF | null
	staticAdTexture?: Texture | null
}

export class FieldBuilder {
	private meshes: Mesh[] = []
	private lines: LineSegments[] = []
	private fatLines: LineSegments2[] = []
	private lineMaterials: LineMaterial[] = []
	private goalModel: Object3D | null = null
	private goalFallbackMeshes: Mesh[] = []
	private goalFallbackLines: LineSegments[] = []

	build(scene: Scene, assets?: FieldAssets) {
		this.buildField(scene, assets?.grassTexture)
		this.buildFieldLines(scene)
		this.buildGoal(scene, assets?.goalGLB)
		this.buildStaticAd(scene, assets?.staticAdTexture)
		this.buildMountains(scene)
		this.buildBackground(scene)
	}

	private buildField(scene: Scene, grassTexture?: Texture | null) {
		let material: MeshStandardMaterial

		if (grassTexture) {
			// wrapping already configured in preloader
			grassTexture.repeat.set(4, 4)
			material = new MeshStandardMaterial({
				map: grassTexture,
				roughness: 0.9,
				metalness: 0.0,
			})
		} else {
			material = new MeshStandardMaterial({
				color: 0x4caf50,
				roughness: 0.9,
				metalness: 0.0,
			})
		}

		// Main field
		const geometry = new PlaneGeometry(FIELD.width, FIELD.length)
		geometry.rotateX(-Math.PI / 2)

		const field = new Mesh(geometry, material)
		field.position.set(0, 0, FIELD.length / 2)
		scene.add(field)
		this.meshes.push(field)

		// Ground behind goal (fills the void behind the net)
		const behindDepth = 4
		const behindGeom = new PlaneGeometry(FIELD.width, behindDepth)
		behindGeom.rotateX(-Math.PI / 2)

		let behindMat: MeshStandardMaterial

		if (grassTexture) {
			// Clone to use different repeat settings
			const behindTexture = grassTexture.clone()
			behindTexture.repeat.set(4, 1)
			behindTexture.needsUpdate = true
			behindMat = new MeshStandardMaterial({
				map: behindTexture,
				roughness: 0.9,
				metalness: 0.0,
			})
		} else {
			behindMat = new MeshStandardMaterial({
				color: 0x4caf50,
				roughness: 0.9,
				metalness: 0.0,
			})
		}

		const behindField = new Mesh(behindGeom, behindMat)
		behindField.position.set(0, 0, -behindDepth / 2)
		scene.add(behindField)
		this.meshes.push(behindField)
	}

	private buildFieldLines(scene: Scene) {
		const halfGoalWidth = GOAL_3D.width / 2
		const sixYardDepth = 5.5
		const sixYardWidth = halfGoalWidth + 5.5
		const penaltyZ = 11

		// --- Near group: crosshair + circle (closest to camera) ---
		const nearVerts: number[] = []
		const circleRadius = 0.6
		const crossSize = circleRadius
		// Horizontal line
		nearVerts.push(-crossSize, 0.01, penaltyZ, crossSize, 0.01, penaltyZ)
		// Vertical line
		nearVerts.push(0, 0.01, penaltyZ - crossSize, 0, 0.01, penaltyZ + crossSize)
		// Circle around crosshair
		const circleSteps = 512
		for (let i = 0; i < circleSteps; i++) {
			const a1 = (Math.PI * 2 * i) / circleSteps
			const a2 = (Math.PI * 2 * (i + 1)) / circleSteps
			nearVerts.push(
				Math.cos(a1) * circleRadius,
				0.01,
				penaltyZ + Math.sin(a1) * circleRadius,
				Math.cos(a2) * circleRadius,
				0.01,
				penaltyZ + Math.sin(a2) * circleRadius
			)
		}

		// --- Mid group: 6-yard box + penalty arc ---
		const midVerts: number[] = []
		// 6-yard box left side
		midVerts.push(-sixYardWidth, 0.01, 0, -sixYardWidth, 0.01, sixYardDepth)
		// 6-yard box right side
		midVerts.push(sixYardWidth, 0.01, 0, sixYardWidth, 0.01, sixYardDepth)
		// 6-yard box bottom
		midVerts.push(
			-sixYardWidth,
			0.01,
			sixYardDepth,
			sixYardWidth,
			0.01,
			sixYardDepth
		)
		// Penalty arc
		const arcRadius = 9.15
		const arcSteps = 20
		for (let i = 0; i < arcSteps; i++) {
			const angle1 = -0.6 + (1.2 * i) / arcSteps
			const angle2 = -0.6 + (1.2 * (i + 1)) / arcSteps
			const x1 = Math.sin(angle1) * arcRadius
			const z1 = penaltyZ - Math.cos(angle1) * arcRadius
			const x2 = Math.sin(angle2) * arcRadius
			const z2 = penaltyZ - Math.cos(angle2) * arcRadius
			if (z1 > sixYardDepth && z2 > sixYardDepth) {
				midVerts.push(x1, 0.01, z1, x2, 0.01, z2)
			}
		}

		// --- Far group: goal line ---
		const farVerts: number[] = []
		farVerts.push(-FIELD.width / 2, 0.01, 0, FIELD.width / 2, 0.01, 0)

		// Create fat line groups
		const groups: { verts: number[]; width: number; opacity: number }[] = [
			{ verts: nearVerts, width: 0.06, opacity: 1.0 },
			{ verts: midVerts, width: 0.05, opacity: 0.9 },
			{ verts: farVerts, width: 0.04, opacity: 0.8 },
		]

		for (const group of groups) {
			const geometry = new LineSegmentsGeometry()
			geometry.setPositions(group.verts)

			const material = new LineMaterial({
				color: 0xffffff,
				linewidth: group.width,
				worldUnits: true,
				transparent: group.opacity < 1,
				opacity: group.opacity,
			})

			const line = new LineSegments2(geometry, material)
			line.computeLineDistances()
			scene.add(line)
			this.fatLines.push(line)
			this.lineMaterials.push(material)
		}
	}

	updateResolution(width: number, height: number) {
		for (const mat of this.lineMaterials) {
			mat.resolution.set(width, height)
		}
	}

	private buildGoal(scene: Scene, goalGLB?: GLTF | null) {
		if (goalGLB) {
			// Use pre-loaded GLB model directly
			this.applyGoalGLB(scene, goalGLB)
		} else {
			// No GLB available — build procedural fallback
			this.buildProceduralGoal(scene)
		}
	}

	private applyGoalGLB(scene: Scene, gltf: GLTF) {
		const model = gltf.scene

		// Rotate 90° counter-clockwise around Y axis
		model.rotation.y = Math.PI / 2

		// Measure the model's bounding box
		const box = new Box3().setFromObject(model)
		const size = new Vector3()
		box.getSize(size)

		// Scale to match GOAL_3D dimensions (non-uniform)
		// After π/2 Y-rotation: model.scale.z → world X (width), .y → world Y (height), .x → world Z (depth)
		const scaleX = GOAL_3D.width / size.x
		const scaleY = GOAL_3D.height / size.y
		model.scale.set(scaleX, scaleY, scaleX)

		// Recompute after scaling
		const scaledBox = new Box3().setFromObject(model)
		const scaledMin = scaledBox.min

		// Position: center on x, bottom on ground (y=0), front posts at z=0
		model.position.x -= (scaledBox.min.x + scaledBox.max.x) / 2
		model.position.y -= scaledMin.y
		model.position.z -= scaledBox.max.z

		// Add the GLB model
		scene.add(model)
		this.goalModel = model
	}

	private buildProceduralGoal(scene: Scene) {
		const halfW = GOAL_3D.width / 2
		const h = GOAL_3D.height
		const d = GOAL_3D.depth
		const r = GOAL_3D.postRadius

		const postMaterial = new MeshStandardMaterial({
			color: 0xffffff,
			roughness: 0.3,
			metalness: 0.6,
		})

		// Left post
		const leftPost = new Mesh(new CylinderGeometry(r, r, h, 8), postMaterial)
		leftPost.position.set(-halfW, h / 2, 0)
		scene.add(leftPost)
		this.meshes.push(leftPost)
		this.goalFallbackMeshes.push(leftPost)

		// Right post
		const rightPost = new Mesh(new CylinderGeometry(r, r, h, 8), postMaterial)
		rightPost.position.set(halfW, h / 2, 0)
		scene.add(rightPost)
		this.meshes.push(rightPost)
		this.goalFallbackMeshes.push(rightPost)

		// Crossbar
		const crossbar = new Mesh(
			new CylinderGeometry(r, r, GOAL_3D.width + r * 2, 8),
			postMaterial
		)
		crossbar.rotation.z = Math.PI / 2
		crossbar.position.set(0, h, 0)
		scene.add(crossbar)
		this.meshes.push(crossbar)
		this.goalFallbackMeshes.push(crossbar)

		// Back posts (vertical supports at back of net)
		const backPostLeft = new Mesh(
			new CylinderGeometry(r * 0.5, r * 0.5, h * 0.8, 6),
			postMaterial
		)
		backPostLeft.position.set(-halfW, (h * 0.8) / 2, -d)
		scene.add(backPostLeft)
		this.meshes.push(backPostLeft)
		this.goalFallbackMeshes.push(backPostLeft)

		const backPostRight = new Mesh(
			new CylinderGeometry(r * 0.5, r * 0.5, h * 0.8, 6),
			postMaterial
		)
		backPostRight.position.set(halfW, (h * 0.8) / 2, -d)
		scene.add(backPostRight)
		this.meshes.push(backPostRight)
		this.goalFallbackMeshes.push(backPostRight)

		// Back crossbar
		const backCrossbar = new Mesh(
			new CylinderGeometry(r * 0.5, r * 0.5, GOAL_3D.width, 6),
			postMaterial
		)
		backCrossbar.rotation.z = Math.PI / 2
		backCrossbar.position.set(0, h * 0.8, -d)
		scene.add(backCrossbar)
		this.meshes.push(backCrossbar)
		this.goalFallbackMeshes.push(backCrossbar)

		// Nets
		this.buildNets(scene)
	}

	private buildNetGrid(
		scene: Scene,
		width: number,
		height: number,
		cols: number,
		rows: number,
		position: { x: number; y: number; z: number },
		rotation: { x: number; y: number; z: number }
	): LineSegments {
		const vertices: number[] = []
		const halfW = width / 2
		const halfH = height / 2

		// Vertical lines
		for (let i = 0; i <= cols; i++) {
			const x = -halfW + (width * i) / cols
			vertices.push(x, -halfH, 0)
			vertices.push(x, halfH, 0)
		}

		// Horizontal lines
		for (let j = 0; j <= rows; j++) {
			const y = -halfH + (height * j) / rows
			vertices.push(-halfW, y, 0)
			vertices.push(halfW, y, 0)
		}

		const geometry = new BufferGeometry()
		geometry.setAttribute('position', new Float32BufferAttribute(vertices, 3))

		const material = new LineBasicMaterial({
			color: 0xffffff,
			transparent: true,
			opacity: 0.35,
		})

		const grid = new LineSegments(geometry, material)
		grid.position.set(position.x, position.y, position.z)
		grid.rotation.set(rotation.x, rotation.y, rotation.z)
		scene.add(grid)
		this.lines.push(grid)
		return grid
	}

	private buildNets(scene: Scene) {
		const halfW = GOAL_3D.width / 2
		const h = GOAL_3D.height
		const d = GOAL_3D.depth
		const backH = h * 0.8

		// Back net
		const backNet = this.buildNetGrid(
			scene,
			GOAL_3D.width,
			backH,
			24,
			16,
			{ x: 0, y: backH / 2, z: -d },
			{ x: 0, y: 0, z: 0 }
		)
		this.goalFallbackLines.push(backNet)

		// Left side net
		const leftNet = this.buildNetGrid(
			scene,
			d,
			h,
			6,
			16,
			{ x: -halfW, y: h / 2, z: -d / 2 },
			{ x: 0, y: Math.PI / 2, z: 0 }
		)
		this.goalFallbackLines.push(leftNet)

		// Right side net
		const rightNet = this.buildNetGrid(
			scene,
			d,
			h,
			6,
			16,
			{ x: halfW, y: h / 2, z: -d / 2 },
			{ x: 0, y: Math.PI / 2, z: 0 }
		)
		this.goalFallbackLines.push(rightNet)

		// Top net (slopes from crossbar down to back)
		const topNetWidth = GOAL_3D.width
		const topNetLength = Math.sqrt(d * d + (h - backH) * (h - backH))
		const slopeAngle = Math.atan2(h - backH, d)
		const topNet = this.buildNetGrid(
			scene,
			topNetWidth,
			topNetLength,
			24,
			6,
			{ x: 0, y: h * 0.9, z: -d / 2 },
			{ x: -Math.PI / 2 + slopeAngle, y: 0, z: 0 }
		)
		this.goalFallbackLines.push(topNet)
	}

	private buildStaticAd(scene: Scene, staticAdTexture?: Texture | null) {
		if (!staticAdTexture) return

		staticAdTexture.wrapS = RepeatWrapping

		const repeats = 3
		const singleWidth = 12
		const totalWidth = singleWidth * repeats
		const adHeight = singleWidth * (45 / 400)

		staticAdTexture.repeat.set(repeats, 1)

		const geometry = new PlaneGeometry(totalWidth, adHeight)
		const material = new MeshBasicMaterial({
			map: staticAdTexture,
			transparent: true,
			side: DoubleSide,
		})

		const ad = new Mesh(geometry, material)
		ad.position.set(0, adHeight / 2, -4)
		scene.add(ad)
		this.meshes.push(ad)
	}

	private buildMountains(scene: Scene) {
		const ranges: {
			z: number
			color: number
			peaks: number[]
		}[] = [
			{
				z: -12,
				color: 0x3a4a5a,
				peaks: [3, 5, 7, 6, 8, 5, 7, 6, 4, 7, 8, 6, 5, 7, 4, 6, 8, 5, 7, 3],
			},
			{
				z: -8,
				color: 0x1a2a3a,
				peaks: [
					2, 3.5, 4, 5, 3, 4.5, 3, 5, 4, 3, 4.5, 5, 3.5, 4, 3, 5, 4, 3.5, 3, 2,
				],
			},
		]

		for (const range of ranges) {
			const segments = range.peaks.length
			const spanX = 50
			const stepX = spanX / segments

			const vertices: number[] = []
			const indices: number[] = []

			for (let i = 0; i <= segments; i++) {
				const x = -spanX / 2 + i * stepX
				const peakY = i < segments ? range.peaks[i] : range.peaks[segments - 1]

				// Bottom vertex
				vertices.push(x, 0, range.z)
				// Top vertex
				vertices.push(x, peakY, range.z)
			}

			for (let i = 0; i < segments; i++) {
				const bl = i * 2
				const tl = i * 2 + 1
				const br = (i + 1) * 2
				const tr = (i + 1) * 2 + 1

				indices.push(bl, br, tl)
				indices.push(tl, br, tr)
			}

			const geometry = new BufferGeometry()
			geometry.setAttribute('position', new Float32BufferAttribute(vertices, 3))
			geometry.setIndex(indices)

			const material = new MeshBasicMaterial({
				color: range.color,
				side: DoubleSide,
			})

			const mesh = new Mesh(geometry, material)
			scene.add(mesh)
			this.meshes.push(mesh)
		}
	}

	private buildBackground(scene: Scene) {
		// Sky sphere with gradient shader
		const skyGeom = new SphereGeometry(50, 32, 16)
		const skyMat = new ShaderMaterial({
			uniforms: {},
			vertexShader: `
				varying vec3 vWorldPosition;
				void main() {
					vec4 worldPos = modelMatrix * vec4(position, 1.0);
					vWorldPosition = worldPos.xyz;
					gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
				}
			`,
			fragmentShader: `
				varying vec3 vWorldPosition;
				void main() {
					float height = normalize(vWorldPosition).y;
					// Horizon: warm light blue, Zenith: deeper blue
					vec3 horizon = vec3(0.6, 0.8, 1.0);
					vec3 zenith = vec3(0.3, 0.5, 0.9);
					float t = max(height, 0.0);
					vec3 color = mix(horizon, zenith, t);
					// Below horizon: slightly darker
					if (height < 0.0) {
						color = mix(vec3(0.5, 0.7, 0.85), horizon, 1.0 + height);
					}
					gl_FragColor = vec4(color, 1.0);
				}
			`,
			side: BackSide,
			depthWrite: false,
		})
		const sky = new Mesh(skyGeom, skyMat)
		scene.add(sky)
		this.meshes.push(sky)
	}

	dispose() {
		for (const mesh of this.meshes) {
			mesh.geometry.dispose()
			if (Array.isArray(mesh.material)) {
				mesh.material.forEach(m => m.dispose())
			} else {
				mesh.material.dispose()
			}
		}
		for (const line of this.lines) {
			line.geometry.dispose()
			;(line.material as LineBasicMaterial).dispose()
		}
		for (const fatLine of this.fatLines) {
			fatLine.geometry.dispose()
			fatLine.material.dispose()
		}
		if (this.goalModel) {
			this.goalModel.traverse(child => {
				if (child instanceof Mesh) {
					child.geometry.dispose()
					if (Array.isArray(child.material)) {
						child.material.forEach(m => m.dispose())
					} else {
						child.material.dispose()
					}
				}
			})
			this.goalModel = null
		}
		this.meshes = []
		this.lines = []
		this.fatLines = []
		this.lineMaterials = []
		this.goalFallbackMeshes = []
		this.goalFallbackLines = []
	}
}
