import {
	Scene,
	Group,
	Mesh,
	PlaneGeometry,
	BoxGeometry,
	MeshBasicMaterial,
	MeshStandardMaterial,
	Texture,
	DoubleSide,
	Box3,
	Vector3,
	BufferAttribute,
} from 'three'
import type { GLTF } from 'three/examples/jsm/loaders/GLTFLoader.js'

const CONFIG = {
	flyHeight: 7,
	flyZ: -5,
	speedX: 6,
	startX: -30,
	endX: 30,
	bobAmplitude: 0.3,
	bobSpeed: 1.5,
	bannerWidth: 8,
	bannerHeight: 8 * (45 / 400), // match ad.png aspect ratio (400x45)
	bannerGap: 1.5,
	bannerSegments: 8,
	waveAmplitude: 0.15,
	waveSpeed: 4,
	planeScale: 5,
}

export class PlaneController {
	private group: Group
	private scene: Scene
	private banner: Mesh | null = null
	private bannerBasePositions: Float32Array | null = null
	private elapsed: number = 0
	private planeTailX: number = -CONFIG.planeScale / 2

	constructor(
		scene: Scene,
		preloadedPlaneGLB?: GLTF | null,
		preloadedPlaneTexture?: Texture | null,
		preloadedFlyingAdTexture?: Texture | null
	) {
		this.scene = scene
		this.group = new Group()
		this.group.position.set(CONFIG.startX, CONFIG.flyHeight, CONFIG.flyZ)
		scene.add(this.group)

		this.buildPlaneModel(preloadedPlaneGLB, preloadedPlaneTexture)
		this.buildBanner(preloadedFlyingAdTexture)
	}

	private buildPlaneModel(
		planeGLB?: GLTF | null,
		planeTexture?: Texture | null
	) {
		if (planeGLB && planeTexture) {
			const model = planeGLB.scene

			// Apply external texture to all meshes
			model.traverse(child => {
				if (child instanceof Mesh) {
					const oldMat = child.material
					child.material = new MeshStandardMaterial({
						map: planeTexture,
						roughness: 0.4,
						metalness: 0.3,
					})
					if (Array.isArray(oldMat)) {
						oldMat.forEach(m => m.dispose())
					} else {
						oldMat.dispose()
					}
				}
			})

			// Measure and scale to target size
			const box = new Box3().setFromObject(model)
			const size = new Vector3()
			box.getSize(size)

			const maxDim = Math.max(size.x, size.y, size.z)
			const scale = CONFIG.planeScale / maxDim
			model.scale.setScalar(scale)

			// Rotate 90° counter-clockwise around Y axis
			model.rotation.y = Math.PI / 2

			// Center the model
			const scaledBox = new Box3().setFromObject(model)
			const center = new Vector3()
			scaledBox.getCenter(center)
			model.position.sub(center)

			// Store actual tail position (min X after centering)
			const centeredBox = new Box3().setFromObject(model)
			this.planeTailX = centeredBox.min.x + 0.5

			this.group.add(model)
		} else {
			// Fallback gray box
			const fallback = new Mesh(
				new BoxGeometry(1.2, 0.4, 0.4),
				new MeshBasicMaterial({ color: 0xcccccc })
			)
			this.group.add(fallback)
		}
	}

	private buildBanner(flyingAdTexture?: Texture | null) {
		// Rope connecting plane tail to banner
		const ropeGeom = new PlaneGeometry(CONFIG.bannerGap, 0.05)
		const ropeMat = new MeshBasicMaterial({
			color: 0x888888,
			side: DoubleSide,
			depthWrite: false,
		})
		const rope = new Mesh(ropeGeom, ropeMat)
		rope.position.set(this.planeTailX - CONFIG.bannerGap / 2, 0, 0)
		this.group.add(rope)

		// Banner with segments for wave animation
		const bannerGeom = new PlaneGeometry(
			CONFIG.bannerWidth,
			CONFIG.bannerHeight,
			CONFIG.bannerSegments,
			1
		)

		const bannerMat = new MeshBasicMaterial({
			map: flyingAdTexture || null,
			side: DoubleSide,
			transparent: true,
			depthWrite: false,
		})

		this.banner = new Mesh(bannerGeom, bannerMat)
		this.banner.position.set(
			this.planeTailX - CONFIG.bannerGap - CONFIG.bannerWidth / 2,
			0,
			0
		)
		this.group.add(this.banner)

		// Store base vertex positions for wave animation
		const posAttr = bannerGeom.getAttribute('position') as BufferAttribute
		this.bannerBasePositions = new Float32Array(posAttr.array.length)
		this.bannerBasePositions.set(posAttr.array)
	}

	update(delta: number) {
		this.elapsed += delta

		// Move along X axis
		this.group.position.x += CONFIG.speedX * delta

		// Wrap around when past endX
		if (this.group.position.x > CONFIG.endX) {
			this.group.position.x = CONFIG.startX
		}

		// Subtle Y bob
		this.group.position.y =
			CONFIG.flyHeight +
			Math.sin(this.elapsed * CONFIG.bobSpeed) * CONFIG.bobAmplitude

		// Banner wave animation
		if (this.banner && this.bannerBasePositions) {
			const posAttr = this.banner.geometry.getAttribute(
				'position'
			) as BufferAttribute
			const basePos = this.bannerBasePositions

			for (let i = 0; i < posAttr.count; i++) {
				const baseX = basePos[i * 3]
				const baseZ = basePos[i * 3 + 2]

				// Normalized distance from leading edge (0 at left/plane side, 1 at trailing end)
				const normalizedDist =
					(baseX + CONFIG.bannerWidth / 2) / CONFIG.bannerWidth

				// Traveling sine wave with amplitude increasing toward trailing edge
				const wave =
					Math.sin(
						this.elapsed * CONFIG.waveSpeed - normalizedDist * Math.PI * 2
					) *
					CONFIG.waveAmplitude *
					normalizedDist

				posAttr.setZ(i, baseZ + wave)
			}

			posAttr.needsUpdate = true
		}
	}

	dispose() {
		this.group.traverse(child => {
			if (child instanceof Mesh) {
				child.geometry.dispose()
				if (Array.isArray(child.material)) {
					child.material.forEach(m => m.dispose())
				} else {
					child.material.dispose()
				}
			}
		})
		this.scene.remove(this.group)
		this.bannerBasePositions = null
	}
}
