import {
	Group,
	Mesh,
	PlaneGeometry,
	MeshBasicMaterial,
	CanvasTexture,
	Scene,
	Camera,
	DoubleSide,
} from 'three'

interface CloudConfig {
	x: number
	y: number
	z: number
	scale: number
	driftSpeed: number
}

function rand(min: number, max: number): number {
	return min + Math.random() * (max - min)
}

function generateConfigs(): CloudConfig[] {
	const count = 5 + Math.floor(Math.random() * 5) // 5-9 clouds
	const configs: CloudConfig[] = []

	for (let i = 0; i < count; i++) {
		const z = rand(-30, -6)
		// Closer clouds (higher z) drift faster
		const depthFactor = (z + 30) / 24 // 0 at z=-30, 1 at z=-6
		const driftSpeed = 0.1 + depthFactor * 0.4

		configs.push({
			x: rand(-20, 20),
			y: rand(14, 26),
			z,
			scale: rand(0.8, 2.0),
			driftSpeed,
		})
	}

	return configs
}

const WRAP_MIN_X = -35
const WRAP_MAX_X = 35

export class CloudController {
	private parent: Group
	private clouds: Group[] = []
	private configs: CloudConfig[]
	private texture: CanvasTexture
	private puffGeometry: PlaneGeometry

	constructor(scene: Scene) {
		this.parent = new Group()
		this.configs = generateConfigs()
		this.texture = this.createPuffTexture()
		this.puffGeometry = new PlaneGeometry(1, 1)

		for (const cfg of this.configs) {
			const cloud = this.buildCloud(cfg)
			this.clouds.push(cloud)
			this.parent.add(cloud)
		}

		scene.add(this.parent)
	}

	private createPuffTexture(): CanvasTexture {
		const size = 128
		const canvas = document.createElement('canvas')
		canvas.width = size
		canvas.height = size
		const ctx = canvas.getContext('2d')!

		const gradient = ctx.createRadialGradient(
			size / 2,
			size / 2,
			0,
			size / 2,
			size / 2,
			size / 2
		)
		gradient.addColorStop(0, 'rgba(255, 255, 255, 1)')
		gradient.addColorStop(0.4, 'rgba(255, 255, 255, 0.6)')
		gradient.addColorStop(0.7, 'rgba(255, 255, 255, 0.15)')
		gradient.addColorStop(1, 'rgba(255, 255, 255, 0)')

		ctx.fillStyle = gradient
		ctx.fillRect(0, 0, size, size)

		const tex = new CanvasTexture(canvas)
		return tex
	}

	private buildCloud(cfg: CloudConfig): Group {
		const group = new Group()
		group.position.set(cfg.x, cfg.y, cfg.z)

		const puffCount = 5 + Math.floor(Math.random() * 4) // 5-8 puffs
		const spreadX = 3.5 * cfg.scale
		const spreadY = 1.2 * cfg.scale
		const spreadZ = 1.5 * cfg.scale

		for (let i = 0; i < puffCount; i++) {
			const material = new MeshBasicMaterial({
				map: this.texture,
				transparent: true,
				opacity: 0.2 + Math.random() * 0.15,
				side: DoubleSide,
				depthWrite: false,
			})

			const puff = new Mesh(this.puffGeometry, material)

			// Random offset within cloud volume
			puff.position.set(
				(Math.random() - 0.5) * spreadX,
				(Math.random() - 0.5) * spreadY,
				(Math.random() - 0.5) * spreadZ
			)

			// Vary puff size
			const puffScale = (2.5 + Math.random() * 2.5) * cfg.scale
			puff.scale.set(puffScale, puffScale, 1)

			group.add(puff)
		}

		return group
	}

	update(delta: number, camera: Camera) {
		for (let i = 0; i < this.clouds.length; i++) {
			const cloud = this.clouds[i]
			const cfg = this.configs[i]

			// Drift leftward
			cloud.position.x -= cfg.driftSpeed * delta

			// Wrap around when exiting left
			if (cloud.position.x < WRAP_MIN_X) {
				cloud.position.x = WRAP_MAX_X
			}

			// Billboard each puff toward camera
			for (const child of cloud.children) {
				child.lookAt(camera.position)
			}
		}
	}

	dispose() {
		this.texture.dispose()
		this.puffGeometry.dispose()

		for (const cloud of this.clouds) {
			for (const child of cloud.children) {
				if (child instanceof Mesh) {
					;(child.material as MeshBasicMaterial).dispose()
				}
			}
		}

		this.parent.removeFromParent()
		this.clouds = []
	}
}
