import {
	Scene,
	Mesh,
	SphereGeometry,
	MeshStandardMaterial,
	Vector3,
	Object3D,
	Box3,
	Texture,
} from 'three'
import type { GLTF } from 'three/examples/jsm/loaders/GLTFLoader.js'
import { BALL_3D, GOAL_3D, DRAG, ROLLING, SPIN_PHYSICS } from '../constants'
import {
	TrajectoryParams,
	getTrajectoryPosition,
	getTrajectoryRotation,
} from '../utils/trajectoryMath'
import { SpinParticles } from './SpinParticles'

export class BallController {
	public mesh: Object3D
	private shadow: Mesh
	private scene: Scene
	private trajectoryParams: TrajectoryParams | null = null
	private flightProgress: number = 0
	private flightDuration: number = 0
	private isFlying: boolean = false
	private onArriveCallback: (() => void) | null = null
	private glbLoaded: boolean = false

	// Drag state (Pokemon GO-style)
	private isDragging: boolean = false
	private dragTargetPosition: Vector3 = new Vector3()
	private dragStartPosition: Vector3 = new Vector3()
	private dragAngularVelocity: number = 0
	private isReturning: boolean = false

	// Rolling state
	private isRolling: boolean = false
	private rollingVelocity: Vector3 = new Vector3()
	private rollingAngularVelocity: number = 0

	// Spin particles
	private spinParticles: SpinParticles

	// Flight trail for charged shots
	private flightCharged: boolean = false
	private flightAngularVelocity: number = 0

	// Trajectory endpoint for reliable scoring
	private trajectoryEndpoint: Vector3 | null = null

	constructor(
		scene: Scene,
		preloadedGLB?: GLTF | null,
		particlesTexture?: Texture | null
	) {
		this.scene = scene

		// Start with a fallback white sphere
		const geometry = new SphereGeometry(
			BALL_3D.radius,
			BALL_3D.segments,
			BALL_3D.segments
		)
		const material = new MeshStandardMaterial({
			color: 0xffffff,
			roughness: 0.15,
			metalness: 0.0,
		})

		this.mesh = new Mesh(geometry, material)
		this.mesh.position.set(
			BALL_3D.startPosition.x,
			BALL_3D.startPosition.y,
			BALL_3D.startPosition.z
		)
		scene.add(this.mesh)

		// Ground shadow (flat dark circle)
		const shadowGeom = new SphereGeometry(BALL_3D.radius * 1.5, 16, 4)
		shadowGeom.scale(1, 0.05, 1)
		const shadowMat = new MeshStandardMaterial({
			color: 0x000000,
			transparent: true,
			opacity: 0.3,
			depthWrite: false,
		})
		this.shadow = new Mesh(shadowGeom, shadowMat)
		this.shadow.position.set(
			BALL_3D.startPosition.x,
			0.01,
			BALL_3D.startPosition.z
		)
		scene.add(this.shadow)

		// Spin particles
		this.spinParticles = new SpinParticles(scene, particlesTexture ?? null)

		// Apply pre-loaded GLB if available
		if (preloadedGLB) {
			this.applyGLBModel(preloadedGLB)
		}
	}

	private applyGLBModel(gltf: GLTF) {
		const model = gltf.scene
		const diameter = BALL_3D.radius * 2

		// Compute bounding boxes and enable shadows
		let maxDim = 0
		model.traverse(child => {
			if (child instanceof Mesh) {
				child.geometry.computeBoundingBox()
				if (child.geometry.boundingBox) {
					const size = new Vector3()
					child.geometry.boundingBox.getSize(size)
					maxDim = Math.max(maxDim, size.x, size.y, size.z)
				}
				if (child.material instanceof MeshStandardMaterial) {
					child.material.roughness = 0.15
					child.material.metalness = 0.0
				}
			}
		})

		// Scale model to match ball diameter
		if (maxDim > 0) {
			model.scale.setScalar(diameter / maxDim)
		} else {
			model.scale.setScalar(diameter)
		}

		// Compute bounding box center (world-space) after scaling
		const box = new Box3().setFromObject(model)
		const center = new Vector3()
		box.getCenter(center)

		// Wrap model in a pivot so rotation is around the geometric center
		const wrapper = new Object3D()
		model.position.set(-center.x, -center.y, -center.z)
		wrapper.add(model)

		// Replace the fallback sphere
		const oldRot = this.mesh.rotation.clone()
		this.scene.remove(this.mesh)
		if (this.mesh instanceof Mesh) {
			this.mesh.geometry.dispose()
			;(this.mesh.material as MeshStandardMaterial).dispose()
		}

		// Position wrapper so ball center is at correct height
		wrapper.position.set(
			BALL_3D.startPosition.x,
			BALL_3D.startPosition.y,
			BALL_3D.startPosition.z
		)
		wrapper.rotation.copy(oldRot)
		this.mesh = wrapper
		this.scene.add(this.mesh)
		this.glbLoaded = true
	}

	// --- Drag methods (Pokemon GO-style) ---

	startDrag() {
		this.isDragging = true
		this.isReturning = false
		this.dragStartPosition.copy(this.mesh.position)
		this.dragTargetPosition.copy(this.mesh.position)
		this.dragAngularVelocity = 0
	}

	updateDrag(
		worldX: number,
		worldY: number,
		worldZ: number,
		angularVelocity: number
	) {
		if (!this.isDragging) return

		// Clamp offsets relative to start position
		const offsetX = Math.max(
			-DRAG.maxOffsetX,
			Math.min(DRAG.maxOffsetX, worldX - this.dragStartPosition.x)
		)
		const offsetY = Math.max(
			0,
			Math.min(DRAG.maxOffsetY, worldY - this.dragStartPosition.y)
		)
		const offsetZ = Math.max(
			-DRAG.maxOffsetZ,
			Math.min(DRAG.maxOffsetZ, worldZ - this.dragStartPosition.z)
		)

		this.dragTargetPosition.set(
			this.dragStartPosition.x + offsetX,
			this.dragStartPosition.y + offsetY,
			this.dragStartPosition.z + offsetZ
		)
		this.dragAngularVelocity = angularVelocity
	}

	endDrag(willShoot: boolean) {
		this.isDragging = false
		this.dragAngularVelocity = 0
		if (!willShoot) {
			this.spinParticles.hide()
			// Return to start position smoothly
			this.isReturning = true
		}
		// If willShoot && flightCharged, particles stay alive (hidden in shoot() if not charged)
	}

	setSpinParticles(angularVelocity: number, isCharged: boolean) {
		this.spinParticles.update(this.mesh.position, angularVelocity, isCharged)
	}

	// --- Shoot methods ---

	shoot(
		targetX: number,
		targetY: number,
		angularVelocity: number,
		isCharged: boolean,
		power: number,
		duration: number,
		onArrive: () => void
	) {
		// Compute endpoint shift for charged shots
		const normalizedSpin = Math.max(
			-1,
			Math.min(1, angularVelocity / SPIN_PHYSICS.maxAngularVelocity)
		)
		let endX = targetX
		if (isCharged) {
			endX = targetX + normalizedSpin * SPIN_PHYSICS.curveInfluence
		}

		const goalZ = GOAL_3D.depth > 0 ? -0.5 : 0

		this.trajectoryParams = {
			start: this.mesh.position.clone(),
			target: new Vector3(endX, targetY, goalZ),
			angularVelocity,
			power,
		}

		// Score at the goal line (z=0) — the actual goalpost plane the user sees —
		// not at the raw endpoint behind the goal (z=-0.5) where arc/curve differ
		const startZ = this.mesh.position.z
		const goalLineT = startZ / (startZ - goalZ)
		const trajectoryAtGoalLine = getTrajectoryPosition(
			this.trajectoryParams,
			goalLineT
		)
		// Override Y: use linear interpolation (no arc) for scoring so the
		// visual parabolic arc doesn't inflate Y above the goal at the goal line
		const linearY =
			this.trajectoryParams.start.y +
			(this.trajectoryParams.target.y - this.trajectoryParams.start.y) *
				goalLineT
		trajectoryAtGoalLine.y = Math.max(BALL_3D.radius, linearY)
		this.trajectoryEndpoint = trajectoryAtGoalLine
		this.flightProgress = 0
		this.flightDuration = duration
		this.isFlying = true
		this.onArriveCallback = onArrive

		// Keep spin particles alive during flight for charged shots
		if (isCharged) {
			this.flightCharged = true
			this.flightAngularVelocity = angularVelocity
		} else {
			this.flightCharged = false
			this.spinParticles.hide()
		}
	}

	shootMiss(
		targetX: number,
		targetY: number,
		angularVelocity: number,
		power: number,
		duration: number,
		onArrive: () => void
	) {
		const normalizedSpin = Math.max(
			-1,
			Math.min(1, angularVelocity / SPIN_PHYSICS.maxAngularVelocity)
		)
		// Miss target: above or wide of the goal
		const missY = GOAL_3D.height + 0.5 + Math.random() * 1.0
		const missX = targetX + normalizedSpin * 1.5 + (Math.random() - 0.5) * 2

		this.trajectoryEndpoint = null // miss — no reliable endpoint needed

		this.trajectoryParams = {
			start: this.mesh.position.clone(),
			target: new Vector3(missX, missY, -2),
			angularVelocity,
			power,
		}
		this.flightProgress = 0
		this.flightDuration = duration
		this.isFlying = true
		this.onArriveCallback = onArrive
		this.flightCharged = false
		this.spinParticles.hide()
	}

	shootShort(
		targetX: number,
		angularVelocity: number,
		duration: number,
		onArrive: () => void
	) {
		const normalizedSpin = Math.max(
			-1,
			Math.min(1, angularVelocity / SPIN_PHYSICS.maxAngularVelocity)
		)

		this.trajectoryEndpoint = null // short — no reliable endpoint needed

		this.trajectoryParams = {
			start: this.mesh.position.clone(),
			target: new Vector3(
				targetX + normalizedSpin * 0.5,
				BALL_3D.radius,
				5 // Falls short, in front of goal
			),
			angularVelocity: angularVelocity * 0.3,
			power: 20,
		}
		this.flightProgress = 0
		this.flightDuration = duration
		this.isFlying = true
		this.onArriveCallback = onArrive
		this.flightCharged = false
		this.spinParticles.hide()
	}

	getTrajectoryEndpoint(): Vector3 | null {
		return this.trajectoryEndpoint
	}

	catch(x: number, y: number, z: number) {
		this.isFlying = false
		this.isRolling = false
		this.flightProgress = 1
		this.flightCharged = false
		this.spinParticles.hide()
		this.onArriveCallback = null
		this.mesh.position.set(x, y, z)
		this.shadow.position.set(x, 0.01, z)
	}

	// --- Update loop (4 modes in priority order) ---

	update(delta: number) {
		if (this.isFlying) {
			this.updateFlight(delta)
		} else if (this.isRolling) {
			this.updateRolling(delta)
		} else if (this.isDragging) {
			this.updateDragFollow(delta)
		} else if (this.isReturning) {
			this.updateReturnToStart(delta)
		}
	}

	private updateFlight(delta: number) {
		if (!this.trajectoryParams) return

		this.flightProgress += (delta * 1000) / this.flightDuration
		const t = Math.min(this.flightProgress, 1)
		const pos = getTrajectoryPosition(this.trajectoryParams, t)

		// Floor collision: if ball hits ground after initial launch phase
		if (pos.y <= BALL_3D.radius && t > 0.3 && t < 1) {
			this.transitionToRolling(t)
			return
		}

		this.mesh.position.copy(pos)

		// Trail spin particles for charged shots
		if (this.flightCharged) {
			this.spinParticles.update(pos, this.flightAngularVelocity, true)
		}

		// Rotation
		const rot = getTrajectoryRotation(this.trajectoryParams.angularVelocity, t)
		this.mesh.rotation.x = rot.x
		this.mesh.rotation.y = rot.y

		// Shadow follows on ground
		this.shadow.position.set(pos.x, 0.01, pos.z)
		const heightAboveGround = pos.y
		const shadowScale = Math.max(0.3, 1 - heightAboveGround * 0.2)
		this.shadow.scale.setScalar(shadowScale)
		;(this.shadow.material as MeshStandardMaterial).opacity = 0.3 * shadowScale

		// Flight complete
		if (this.flightProgress >= 1) {
			this.flightProgress = 1
			this.isFlying = false
			this.flightCharged = false
			this.spinParticles.hide()

			const finalPos = getTrajectoryPosition(this.trajectoryParams, 1)
			this.mesh.position.copy(finalPos)

			this.shadow.position.set(finalPos.x, 0.01, finalPos.z)
			this.shadow.scale.setScalar(0.5)
			;(this.shadow.material as MeshStandardMaterial).opacity = 0.1

			if (this.onArriveCallback) {
				this.onArriveCallback()
				this.onArriveCallback = null
			}
		}
	}

	private transitionToRolling(t: number) {
		if (!this.trajectoryParams) return

		this.flightCharged = false
		this.spinParticles.hide()

		// Place ball on ground
		this.mesh.position.y = ROLLING.groundY

		// Calculate rolling velocity from trajectory direction
		const epsilon = 0.02
		const posCurrent = getTrajectoryPosition(this.trajectoryParams, t)
		const posNext = getTrajectoryPosition(
			this.trajectoryParams,
			Math.min(1, t + epsilon)
		)
		const dir = posNext.clone().sub(posCurrent).normalize()

		// Speed proportional to power and remaining flight
		const speed = (this.trajectoryParams.power / 100) * 3 * (1 - t)
		this.rollingVelocity.set(dir.x * speed, 0, dir.z * speed)
		this.rollingAngularVelocity = speed / BALL_3D.radius

		this.isFlying = false
		this.isRolling = true

		// Fire onArrive after a short delay to let rolling animation play
		if (this.onArriveCallback) {
			const cb = this.onArriveCallback
			this.onArriveCallback = null
			setTimeout(() => cb(), 800)
		}
	}

	private updateRolling(_delta: number) {
		// Apply friction
		this.rollingVelocity.multiplyScalar(ROLLING.friction)
		this.rollingAngularVelocity *= ROLLING.friction

		// Move ball
		this.mesh.position.add(this.rollingVelocity)
		this.mesh.position.y = ROLLING.groundY

		// Forward roll rotation
		this.mesh.rotation.x += this.rollingAngularVelocity * 0.1

		// Shadow follows
		this.shadow.position.set(this.mesh.position.x, 0.01, this.mesh.position.z)
		this.shadow.scale.setScalar(1)
		;(this.shadow.material as MeshStandardMaterial).opacity = 0.3

		// Stop when slow enough
		if (this.rollingVelocity.length() < ROLLING.minVelocity) {
			this.isRolling = false
			this.rollingVelocity.set(0, 0, 0)
			this.rollingAngularVelocity = 0
		}
	}

	private updateDragFollow(_delta: number) {
		// Lerp toward drag target
		this.mesh.position.lerp(this.dragTargetPosition, DRAG.followSpeed)

		// Z-axis rotation driven by angular velocity (clockwise gesture = clockwise visual spin)
		this.mesh.rotation.z -=
			this.dragAngularVelocity * DRAG.spinRotationSpeed * 0.016

		// Shadow follows
		this.shadow.position.set(this.mesh.position.x, 0.01, this.mesh.position.z)
	}

	private updateReturnToStart(_delta: number) {
		const startPos = new Vector3(
			BALL_3D.startPosition.x,
			BALL_3D.startPosition.y,
			BALL_3D.startPosition.z
		)

		this.mesh.position.lerp(startPos, DRAG.returnSpeed)

		// Unwind rotation back to zero
		this.mesh.rotation.x *= 1 - DRAG.returnSpeed
		this.mesh.rotation.y *= 1 - DRAG.returnSpeed
		this.mesh.rotation.z *= 1 - DRAG.returnSpeed

		// Shadow follows
		this.shadow.position.set(this.mesh.position.x, 0.01, this.mesh.position.z)

		// Close enough — snap to start
		if (this.mesh.position.distanceTo(startPos) < 0.01) {
			this.mesh.position.copy(startPos)
			this.mesh.rotation.set(0, 0, 0)
			this.isReturning = false
		}
	}

	reset() {
		this.mesh.position.set(
			BALL_3D.startPosition.x,
			BALL_3D.startPosition.y,
			BALL_3D.startPosition.z
		)
		this.mesh.rotation.set(0, 0, 0)
		this.shadow.position.set(
			BALL_3D.startPosition.x,
			0.01,
			BALL_3D.startPosition.z
		)
		this.shadow.scale.setScalar(1)
		;(this.shadow.material as MeshStandardMaterial).opacity = 0.3
		this.isFlying = false
		this.trajectoryParams = null
		this.trajectoryEndpoint = null
		this.flightProgress = 0
		this.onArriveCallback = null

		// Clear drag state
		this.isDragging = false
		this.isReturning = false
		this.dragAngularVelocity = 0
		this.flightCharged = false
		this.flightAngularVelocity = 0
		this.spinParticles.hide()

		// Clear rolling state
		this.isRolling = false
		this.rollingVelocity.set(0, 0, 0)
		this.rollingAngularVelocity = 0
	}

	getPosition(): Vector3 {
		return this.mesh.position.clone()
	}

	get flying(): boolean {
		return this.isFlying
	}

	dispose() {
		if (this.mesh instanceof Mesh) {
			this.mesh.geometry.dispose()
			;(this.mesh.material as MeshStandardMaterial).dispose()
		} else {
			// GLB model: traverse and dispose all meshes
			this.mesh.traverse(child => {
				if (child instanceof Mesh) {
					child.geometry.dispose()
					if (Array.isArray(child.material)) {
						child.material.forEach(m => m.dispose())
					} else {
						child.material.dispose()
					}
				}
			})
		}
		this.shadow.geometry.dispose()
		;(this.shadow.material as MeshStandardMaterial).dispose()
		this.spinParticles.dispose()
		this.scene.remove(this.mesh)
		this.scene.remove(this.shadow)
	}
}
