import {
	Scene,
	Sprite,
	SpriteMaterial,
	Texture,
	CanvasTexture,
	AdditiveBlending,
	Vector3,
	Color,
	BufferGeometry,
	Float32BufferAttribute,
	MeshBasicMaterial,
	Mesh,
	DoubleSide,
} from 'three'
import { SPIN_PHYSICS } from '../constants'

const POOL_SIZE = 16
const SPRITE_SHEET_FRAMES = 9
const SPAWN_RADIUS = 0.35
// Particles appear before fully charged (30% of charge threshold)
const SHOW_THRESHOLD = SPIN_PHYSICS.chargeThreshold * 0.3
const MAX_EMISSION_RATE = 32 // particles per second when fully charged

interface Particle {
	sprite: Sprite
	material: SpriteMaterial
	alive: boolean
	age: number
	lifetime: number
	offset: Vector3 // position offset from ball center
	velocity: Vector3 // outward drift velocity
	spinRate: number // radians/sec rotation of the sprite itself
	initialScale: number
	frameIndex: number
}

// Arc configuration for each swoosh ribbon
const ARC_CONFIGS = [
	{
		radius: 0.32,
		angle: (2 * Math.PI) / 3,
		width: 0.04,
		yOffset: -0.05,
		initialRotation: 0,
	},
	{
		radius: 0.35,
		angle: (5 * Math.PI) / 9,
		width: 0.045,
		yOffset: 0.03,
		initialRotation: (2 * Math.PI) / 3,
	},
	{
		radius: 0.3,
		angle: (4 * Math.PI) / 9,
		width: 0.035,
		yOffset: 0.1,
		initialRotation: (4 * Math.PI) / 3,
	},
]

export class SpinParticles {
	private particles: Particle[] = []
	private frameTextures: Texture[] = []
	private fallbackTexture: CanvasTexture | null = null
	private scene: Scene
	private active: boolean = false
	private emissionAccumulator: number = 0
	private lastTime: number = 0

	private colorStart = new Color(1.0, 0.75, 0.0) // vivid yellow
	private colorEnd = new Color(1.0, 0.4, 0.0) // deep orange-amber

	// Arc swoosh properties
	private arcMeshes: Mesh[] = []
	private arcMaterials: MeshBasicMaterial[] = []
	private arcYOffsets: number[] = []
	private arcInitialRotations: number[] = []
	private arcTexture: CanvasTexture | null = null
	private arcOpacity: number = 0
	private arcRotation: number = 0

	constructor(scene: Scene, particlesTexture: Texture | null) {
		this.scene = scene
		this.lastTime = performance.now() / 1000

		// Slice sprite sheet into 9 frame textures
		if (particlesTexture) {
			for (let i = 0; i < SPRITE_SHEET_FRAMES; i++) {
				const tex = particlesTexture.clone()
				tex.repeat.set(1 / SPRITE_SHEET_FRAMES, 1)
				tex.offset.set(i / SPRITE_SHEET_FRAMES, 0)
				tex.needsUpdate = true
				this.frameTextures.push(tex)
			}
		} else {
			// Fallback procedural glow
			this.fallbackTexture = this.createGlowTexture()
		}

		// Pre-create pool of sprites (all hidden)
		for (let i = 0; i < POOL_SIZE; i++) {
			const material = new SpriteMaterial({
				map: this.fallbackTexture || this.frameTextures[0],
				blending: AdditiveBlending,
				transparent: true,
				opacity: 0,
				depthWrite: false,
				alphaTest: 0.01,
			})
			const sprite = new Sprite(material)
			sprite.scale.setScalar(0.08)
			sprite.visible = false
			scene.add(sprite)

			this.particles.push({
				sprite,
				material,
				alive: false,
				age: 0,
				lifetime: 0.15,
				offset: new Vector3(),
				velocity: new Vector3(),
				spinRate: 0,
				initialScale: 0.1,
				frameIndex: 0,
			})
		}

		// Create arc swoosh meshes
		this.createArcs()
	}

	private createGlowTexture(): CanvasTexture {
		const size = 64
		const canvas = document.createElement('canvas')
		canvas.width = size
		canvas.height = size
		const ctx = canvas.getContext('2d')!

		const gradient = ctx.createRadialGradient(
			size / 2,
			size / 2,
			0,
			size / 2,
			size / 2,
			size / 2
		)
		gradient.addColorStop(0, 'rgba(255, 200, 50, 1)')
		gradient.addColorStop(0.3, 'rgba(255, 170, 0, 0.8)')
		gradient.addColorStop(1, 'rgba(255, 120, 0, 0)')

		ctx.fillStyle = gradient
		ctx.fillRect(0, 0, size, size)

		return new CanvasTexture(canvas)
	}

	private createArcTexture(): CanvasTexture {
		const w = 256
		const h = 16
		const canvas = document.createElement('canvas')
		canvas.width = w
		canvas.height = h
		const ctx = canvas.getContext('2d')!

		// Horizontal gradient: transparent → white → transparent (tapered ends)
		const hGrad = ctx.createLinearGradient(0, 0, w, 0)
		hGrad.addColorStop(0, 'rgba(255, 255, 255, 0)')
		hGrad.addColorStop(0.15, 'rgba(255, 255, 255, 1)')
		hGrad.addColorStop(0.5, 'rgba(255, 255, 255, 1)')
		hGrad.addColorStop(0.85, 'rgba(255, 255, 255, 1)')
		hGrad.addColorStop(1, 'rgba(255, 255, 255, 0)')
		ctx.fillStyle = hGrad
		ctx.fillRect(0, 0, w, h)

		// Vertical gradient: soft edge → bright center → soft edge (multiply via compositing)
		ctx.globalCompositeOperation = 'destination-in'
		const vGrad = ctx.createLinearGradient(0, 0, 0, h)
		vGrad.addColorStop(0, 'rgba(255, 255, 255, 0)')
		vGrad.addColorStop(0.3, 'rgba(255, 255, 255, 1)')
		vGrad.addColorStop(0.5, 'rgba(255, 255, 255, 1)')
		vGrad.addColorStop(0.7, 'rgba(255, 255, 255, 1)')
		vGrad.addColorStop(1, 'rgba(255, 255, 255, 0)')
		ctx.fillStyle = vGrad
		ctx.fillRect(0, 0, w, h)

		return new CanvasTexture(canvas)
	}

	private createArcGeometry(
		radius: number,
		arcAngle: number,
		width: number,
		segments: number = 24
	): BufferGeometry {
		const positions: number[] = []
		const uvs: number[] = []
		const indices: number[] = []

		const halfWidth = width / 2
		const startAngle = -arcAngle / 2

		for (let i = 0; i <= segments; i++) {
			const t = i / segments
			const angle = startAngle + t * arcAngle

			const cosA = Math.cos(angle)
			const sinA = Math.sin(angle)

			// Inner vertex (closer to center)
			const innerR = radius - halfWidth
			positions.push(sinA * innerR, 0, cosA * innerR)
			uvs.push(t, 0)

			// Outer vertex (farther from center)
			const outerR = radius + halfWidth
			positions.push(sinA * outerR, 0, cosA * outerR)
			uvs.push(t, 1)

			// Triangle indices (two triangles per quad)
			if (i < segments) {
				const base = i * 2
				indices.push(base, base + 1, base + 2)
				indices.push(base + 1, base + 3, base + 2)
			}
		}

		const geometry = new BufferGeometry()
		geometry.setAttribute('position', new Float32BufferAttribute(positions, 3))
		geometry.setAttribute('uv', new Float32BufferAttribute(uvs, 2))
		geometry.setIndex(indices)

		return geometry
	}

	private createArcs() {
		this.arcTexture = this.createArcTexture()

		for (const config of ARC_CONFIGS) {
			const geometry = this.createArcGeometry(
				config.radius,
				config.angle,
				config.width
			)
			const material = new MeshBasicMaterial({
				map: this.arcTexture,
				transparent: true,
				opacity: 0,
				blending: AdditiveBlending,
				depthWrite: false,
				side: DoubleSide,
			})
			const mesh = new Mesh(geometry, material)
			mesh.visible = false
			this.scene.add(mesh)

			this.arcMeshes.push(mesh)
			this.arcMaterials.push(material)
			this.arcYOffsets.push(config.yOffset)
			this.arcInitialRotations.push(config.initialRotation)
		}
	}

	private spawnParticle(
		ballPosition: Vector3,
		intensity: number,
		isCharged: boolean
	) {
		// Find a dead particle to recycle
		const p = this.particles.find(p => !p.alive)
		if (!p) return

		p.alive = true
		p.age = 0
		p.lifetime = 0.3 + Math.random() * 0.3 // 0.3-0.6s

		// Random position on sphere around ball
		const theta = Math.random() * Math.PI * 2
		const phi = Math.acos(2 * Math.random() - 1)
		p.offset.set(
			Math.sin(phi) * Math.cos(theta) * SPAWN_RADIUS,
			Math.sin(phi) * Math.sin(theta) * SPAWN_RADIUS,
			Math.cos(phi) * SPAWN_RADIUS * 0.5 // flatten slightly in Z
		)

		// Outward drift velocity
		const driftSpeed = isCharged
			? 0.6 + Math.random() * 0.2
			: 0.4 + Math.random() * 0.2
		p.velocity.copy(p.offset).normalize().multiplyScalar(driftSpeed)

		// Random star frame — bias toward larger stars (higher indices) when charged
		if (this.frameTextures.length > 0) {
			if (isCharged) {
				// Bias toward frames 5-8 (larger stars)
				p.frameIndex = Math.floor(Math.random() * 4) + SPRITE_SHEET_FRAMES - 4
			} else {
				// Bias toward smaller frames based on intensity
				const maxFrame = Math.floor(2 + intensity * (SPRITE_SHEET_FRAMES - 2))
				p.frameIndex = Math.floor(Math.random() * maxFrame)
			}
			p.frameIndex = Math.min(p.frameIndex, SPRITE_SHEET_FRAMES - 1)
			p.material.map = this.frameTextures[p.frameIndex]
			p.material.needsUpdate = true
		}

		// Random spin rate: ±360°/lifetime
		p.spinRate = ((Math.random() - 0.5) * 2 * Math.PI * 2) / p.lifetime

		// Scale: bigger when charged
		p.initialScale = isCharged
			? 0.16 + Math.random() * 0.1
			: 0.1 + Math.random() * 0.06 * intensity

		// Position
		p.sprite.position.set(
			ballPosition.x + p.offset.x,
			ballPosition.y + p.offset.y,
			ballPosition.z + p.offset.z
		)
		p.sprite.visible = true
	}

	update(ballPosition: Vector3, angularVelocity: number, isCharged: boolean) {
		const now = performance.now() / 1000
		const dt = Math.min(now - this.lastTime, 0.05) // cap at 50ms
		this.lastTime = now

		const absAngVel = Math.abs(angularVelocity)

		if (absAngVel < SHOW_THRESHOLD) {
			if (this.active) this.hide()
			return
		}

		this.active = true

		// Intensity ramp: 0 at SHOW_THRESHOLD → 1.0 at chargeThreshold
		const rampRange = SPIN_PHYSICS.chargeThreshold - SHOW_THRESHOLD
		const intensity = Math.min(1, (absAngVel - SHOW_THRESHOLD) / rampRange)

		// Emission rate scales with intensity
		const emissionRate = intensity * MAX_EMISSION_RATE
		this.emissionAccumulator += emissionRate * dt

		// Spawn particles from accumulator
		while (this.emissionAccumulator >= 1) {
			this.spawnParticle(ballPosition, intensity, isCharged)
			this.emissionAccumulator -= 1
		}

		// Update live particles
		const lerpColor = new Color()
		for (const p of this.particles) {
			if (!p.alive) continue

			p.age += dt

			// Recycle when expired
			if (p.age >= p.lifetime) {
				p.alive = false
				p.sprite.visible = false
				p.material.opacity = 0
				continue
			}

			const t = p.age / p.lifetime // 0→1 over lifetime

			// Drift outward
			p.offset.addScaledVector(p.velocity, dt)

			// Position follows ball + offset
			p.sprite.position.set(
				ballPosition.x + p.offset.x,
				ballPosition.y + p.offset.y,
				ballPosition.z + p.offset.z
			)

			// Scale animation: pop in, then shrink out
			const scaleCurve = t < 0.3 ? t / 0.3 : 1 - (t - 0.3) / 0.7
			const s = p.initialScale * scaleCurve
			p.sprite.scale.set(Math.max(0.01, s), Math.max(0.01, s), 1)

			// Sprite rotation
			p.material.rotation += p.spinRate * dt

			// Opacity: fade in first 20%, fade out last 30%
			let opacity = 1
			if (t < 0.2) {
				opacity = t / 0.2
			} else if (t > 0.7) {
				opacity = (1 - t) / 0.3
			}
			p.material.opacity = opacity * (isCharged ? 1.0 : 0.7 + intensity * 0.3)

			// Color: lerp golden → deep amber
			lerpColor.copy(this.colorStart).lerp(this.colorEnd, t)
			p.material.color.copy(lerpColor)
		}

		// Update arc swooshes
		this.updateArcs(ballPosition, angularVelocity, intensity, isCharged, dt)
	}

	private updateArcs(
		ballPosition: Vector3,
		angularVelocity: number,
		intensity: number,
		isCharged: boolean,
		dt: number
	) {
		// Accumulate rotation in spin direction
		this.arcRotation += angularVelocity * (isCharged ? 1.0 : 0.8) * dt

		// Target opacity based on intensity and charge state
		const targetOpacity = intensity * (isCharged ? 0.9 : 0.6)

		// Smooth lerp toward target
		this.arcOpacity += (targetOpacity - this.arcOpacity) * Math.min(1, dt * 8)

		for (let i = 0; i < this.arcMeshes.length; i++) {
			const mesh = this.arcMeshes[i]
			const material = this.arcMaterials[i]

			// Position: follow ball with Y offset
			mesh.position.set(
				ballPosition.x,
				ballPosition.y + this.arcYOffsets[i],
				ballPosition.z
			)

			// Rotation: accumulated spin + stagger offset
			mesh.rotation.y = this.arcRotation + this.arcInitialRotations[i]

			// Per-arc opacity variation for depth
			const opacityVariation = 1.0 - i * 0.1
			material.opacity = this.arcOpacity * opacityVariation

			// Show when we have some opacity
			mesh.visible = material.opacity > 0.01
		}
	}

	hide() {
		this.active = false
		this.emissionAccumulator = 0
		for (const p of this.particles) {
			p.alive = false
			p.sprite.visible = false
			p.material.opacity = 0
		}
		// Hide arcs
		this.arcOpacity = 0
		this.arcRotation = 0
		for (let i = 0; i < this.arcMeshes.length; i++) {
			this.arcMeshes[i].visible = false
			this.arcMaterials[i].opacity = 0
		}
	}

	dispose() {
		for (const p of this.particles) {
			this.scene.remove(p.sprite)
			p.material.dispose()
		}
		for (const tex of this.frameTextures) {
			tex.dispose()
		}
		if (this.fallbackTexture) {
			this.fallbackTexture.dispose()
		}
		// Dispose arcs
		for (const mesh of this.arcMeshes) {
			this.scene.remove(mesh)
			mesh.geometry.dispose()
		}
		for (const mat of this.arcMaterials) {
			mat.dispose()
		}
		if (this.arcTexture) {
			this.arcTexture.dispose()
		}
		this.particles = []
		this.frameTextures = []
		this.arcMeshes = []
		this.arcMaterials = []
	}
}
