import { Vector3 } from 'three'
import { SceneManager } from './SceneManager'
import { FieldBuilder } from './FieldBuilder'
import { BallController } from './BallController'
import { GoalkeeperController } from './GoalkeeperController'
import { PlaneController } from './PlaneController'
import { InputManager, ShotInput } from './InputManager'
import { AssetPreloader } from './AssetPreloader'
import { CloudController } from './CloudController'
import { screenDragToGoalTarget } from '../utils/trajectoryMath'
import { penaltyShootoutAudio } from '../utils/audioManager'
import {
	GOAL_3D,
	BALL_3D,
	GOALKEEPER_3D,
	SCORING,
	DIFFICULTY,
	TIMING,
	TOTAL_ROUNDS,
	SPIN_PHYSICS,
} from '../constants'
import {
	GameState,
	GamePhase,
	ShotResult,
	GoalkeeperDifficulty,
	GameCallbacks,
} from '../types'

export class GameStateMachine {
	private sceneManager: SceneManager
	private fieldBuilder!: FieldBuilder
	private ball!: BallController
	private goalkeeper!: GoalkeeperController
	private plane!: PlaneController
	private clouds!: CloudController
	private input!: InputManager

	private state: GameState
	private currentDifficulty: GoalkeeperDifficulty
	private totalRounds: number
	private callbacks: GameCallbacks
	private container: HTMLElement
	private isDisposed: boolean = false

	// Shot tracking
	private lastDiveDirection: 'left' | 'right' | 'center' = 'center'
	private lastShotPower: number = 0
	private lastCurveAmount: number = 0
	private lastShotCharged: boolean = false
	private lastAimTarget: { x: number; y: number } = { x: 0, y: 0 }
	private shotResults: ShotResult[] = []

	// UI state exposed to React
	public uiState = {
		round: 1,
		totalRounds: TOTAL_ROUNDS,
		phase: 'loading' as GamePhase,
		result: null as ShotResult,
		resultText: '',
		resultColor: '#ffffff',
		power: 30,
		spin: 0,
		shotResults: [] as ShotResult[],
		isDragging: false,
		loadProgress: 0,
		totalScore: 0,
	}

	constructor(
		container: HTMLElement,
		callbacks: GameCallbacks,
		totalRounds: number = TOTAL_ROUNDS
	) {
		this.callbacks = callbacks
		this.totalRounds = totalRounds
		this.container = container
		this.uiState.totalRounds = totalRounds

		// Initialize scene (renderer, camera, lights)
		this.sceneManager = new SceneManager(container)

		// Initial state
		this.state = {
			phase: 'loading',
			round: 1,
			goals: 0,
			totalScore: 0,
			lastResult: null,
			consecutiveGoals: 0,
			aimPosition: null,
			power: 0,
		}
		this.currentDifficulty = DIFFICULTY[1]
		this.shotResults = []

		// Register update callback (safe with null guards)
		this.sceneManager.onUpdate(delta => this.update(delta))

		// Start render loop (renders empty scene with sky behind loading overlay)
		this.sceneManager.start()

		// Begin async initialization
		this.init()
	}

	private async init() {
		// Load all assets with progress tracking
		const preloader = new AssetPreloader()
		const assets = await preloader.load((loaded, total) => {
			this.uiState.loadProgress = loaded / total
		})

		// If component unmounted during load, bail out
		if (this.isDisposed) return

		// Create all controllers with pre-loaded assets
		this.fieldBuilder = new FieldBuilder()
		this.fieldBuilder.build(this.sceneManager.scene, {
			grassTexture: assets.grassTexture,
			goalGLB: assets.goalGLB,
			staticAdTexture: assets.staticAdTexture,
		})

		this.clouds = new CloudController(this.sceneManager.scene)

		// Set initial resolution for fat line materials and keep in sync on resize
		const canvas = this.sceneManager.renderer.domElement
		this.fieldBuilder.updateResolution(canvas.clientWidth, canvas.clientHeight)
		this.sceneManager.onResize((w, h) =>
			this.fieldBuilder.updateResolution(w, h)
		)

		this.ball = new BallController(
			this.sceneManager.scene,
			assets.ballGLB,
			assets.particlesTexture
		)
		this.goalkeeper = new GoalkeeperController(
			this.sceneManager.scene,
			assets.goalkeeperTexture
		)
		this.plane = new PlaneController(
			this.sceneManager.scene,
			assets.planeGLB,
			assets.planeTexture,
			assets.flyingAdTexture
		)
		this.input = new InputManager(this.container)

		// Set ball screen position for input hit testing
		this.updateBallScreenPosition()

		// Setup input handlers
		this.input.onShot(shot => this.handleShot(shot))
		this.input.onDragUpdate((_dx, _dy, angularVelocity, isCharged, power) => {
			this.uiState.power = power
			this.uiState.spin = angularVelocity

			// Project screen drag to 3D world and update ball
			if (this.state.phase === 'aiming') {
				const worldPos = this.screenToWorldAtZ(
					this.input.ballScreenX,
					this.input.ballScreenY,
					BALL_3D.startPosition.z
				)
				if (worldPos) {
					this.ball.updateDrag(
						worldPos.x,
						worldPos.y,
						worldPos.z,
						angularVelocity
					)
				}
				this.ball.setSpinParticles(angularVelocity, isCharged)
			}
		})

		// Drag lifecycle callbacks
		this.input.onDragStart(() => {
			if (this.state.phase === 'aiming') {
				this.uiState.isDragging = true
				this.ball.startDrag()
			}
		})
		this.input.onDragEnd((firedShot: boolean) => {
			if (this.state.phase === 'aiming') {
				this.uiState.isDragging = false
				this.ball.endDrag(firedShot)
			}
		})

		// Initialize audio
		penaltyShootoutAudio.init()

		this.setPhase('start')
	}

	private updateBallScreenPosition() {
		// Project ball 3D position to screen coordinates
		const vector = this.ball.mesh.position.clone()
		vector.project(this.sceneManager.camera)

		const canvas = this.sceneManager.renderer.domElement
		const halfWidth = canvas.clientWidth / 2
		const halfHeight = canvas.clientHeight / 2

		const screenX = vector.x * halfWidth + halfWidth
		const screenY = -(vector.y * halfHeight) + halfHeight

		this.input.setBallPosition(screenX, screenY, 40)
	}

	private setPhase(phase: GamePhase) {
		this.state.phase = phase
		this.uiState.phase = phase
		this.callbacks.onPhaseChange?.(phase)
	}

	startGame() {
		if (this.state.phase !== 'start') return
		this.startRound()
	}

	private startRound() {
		this.currentDifficulty = DIFFICULTY[Math.min(this.state.round, 5)]
		this.uiState.round = this.state.round
		this.uiState.totalRounds = this.totalRounds
		this.uiState.result = null
		this.uiState.resultText = ''
		this.uiState.power = 30
		this.uiState.spin = 0
		this.uiState.isDragging = false
		this.lastShotCharged = false

		// Reset positions
		this.ball.reset()
		this.goalkeeper.reset()
		this.updateBallScreenPosition()

		// Enable input
		this.input.enable()
		this.setPhase('aiming')
	}

	private handleShot(shotInput: ShotInput) {
		if (this.state.phase !== 'aiming') return

		this.input.disable()
		this.setPhase('shooting')

		// End drag before shooting — trajectory starts from current ball position
		this.ball.endDrag(true)

		penaltyShootoutAudio.playKick()

		const { power, angularVelocity, isCharged, directionX } = shotInput
		this.state.power = power
		this.lastShotPower = power

		// Calculate normalized curve amount for GK save check
		this.lastCurveAmount = Math.min(
			1,
			Math.abs(angularVelocity) / SPIN_PHYSICS.maxAngularVelocity
		)
		this.lastShotCharged = isCharged

		// Map input to 3D goal target
		const target = screenDragToGoalTarget(
			directionX,
			power,
			GOAL_3D.width,
			GOAL_3D.height
		)
		this.lastAimTarget = target
		this.state.aimPosition = target

		// Check for weak shot
		if (power < 35) {
			this.ball.shootShort(target.x, angularVelocity, 500, () => {
				this.resolveResult('miss')
			})
			return
		}

		// Calculate effective target X (including charged shift) for GK decision
		const normalizedSpin = Math.max(
			-1,
			Math.min(1, angularVelocity / SPIN_PHYSICS.maxAngularVelocity)
		)
		let effectiveTargetX = target.x
		if (isCharged) {
			effectiveTargetX += normalizedSpin * SPIN_PHYSICS.curveInfluence
		}

		// Decide goalkeeper dive based on effective target
		this.lastDiveDirection = this.goalkeeper.decideDive(
			effectiveTargetX,
			angularVelocity,
			this.currentDifficulty
		)

		// Check for miss (over the bar)
		const missChance = power > 95 ? 0.25 : power > 90 ? 0.1 : 0
		if (Math.random() < missChance) {
			this.ball.shootMiss(
				target.x,
				target.y,
				angularVelocity,
				power,
				600,
				() => {
					this.resolveResult('miss')
				}
			)
			// GK still dives
			setTimeout(() => {
				this.goalkeeper.dive(this.lastDiveDirection)
			}, this.currentDifficulty.reactionSpeed)
			return
		}

		// Regular shot
		const travelDuration = TIMING.ballTravelDuration * (1.8 - power / 150)

		this.ball.shoot(
			target.x,
			target.y,
			angularVelocity,
			isCharged,
			power,
			travelDuration,
			() => {
				// Use trajectory endpoint for deterministic scoring
				const endpoint = this.ball.getTrajectoryEndpoint()
				if (!endpoint) {
					this.resolveResult('miss')
					return
				}

				// Check if ball EDGE is within goal frame (subtract radius so
				// the ball can't visually protrude past posts/crossbar)
				const halfGoalWidth = GOAL_3D.width / 2 - BALL_3D.radius
				const maxHeight = GOAL_3D.height - BALL_3D.radius
				if (Math.abs(endpoint.x) > halfGoalWidth || endpoint.y > maxHeight) {
					this.resolveResult('miss')
					return
				}

				const isSaved = this.goalkeeper.checkSave(
					endpoint,
					this.lastDiveDirection,
					this.currentDifficulty,
					this.lastShotPower,
					this.lastCurveAmount
				)

				if (isSaved) {
					this.goalkeeper.snapToSave(endpoint.x, endpoint.y)
					this.ball.catch(
						endpoint.x,
						Math.max(BALL_3D.radius, endpoint.y),
						GOALKEEPER_3D.startPosition.z
					)
				}

				this.resolveResult(isSaved ? 'save' : 'goal')
			}
		)

		// Goalkeeper reacts after delay
		setTimeout(() => {
			this.goalkeeper.dive(this.lastDiveDirection)
		}, this.currentDifficulty.reactionSpeed)
	}

	private resolveResult(result: ShotResult) {
		this.state.lastResult = result

		// Play sound
		if (result === 'goal') {
			penaltyShootoutAudio.playGoal()
		} else if (result === 'save') {
			penaltyShootoutAudio.playSave()
		} else {
			penaltyShootoutAudio.playMiss()
		}

		// Calculate score
		let points = 0
		const bonuses = { corner: false, curve: false, streak: 0 }

		if (result === 'goal') {
			points = SCORING.baseGoal

			// Corner bonus
			const isCorner =
				this.lastAimTarget.y > GOAL_3D.height * 0.6 &&
				Math.abs(this.lastAimTarget.x) > GOAL_3D.width / 3
			if (isCorner) {
				points += SCORING.cornerBonus
				bonuses.corner = true
			}

			// Curve bonus — use isCharged flag (player performed circular gesture)
			if (this.lastShotCharged) {
				points += SCORING.perfectPowerBonus
				bonuses.curve = true
			}

			// Streak
			this.state.consecutiveGoals++
			if (this.state.consecutiveGoals > 1) {
				const streakBonus =
					(this.state.consecutiveGoals - 1) * SCORING.streakBonusPerGoal
				points += streakBonus
				bonuses.streak = this.state.consecutiveGoals
			}

			this.state.goals++
			this.state.totalScore += points
			this.uiState.totalScore = this.state.totalScore
		} else {
			this.state.consecutiveGoals = 0
		}

		// Track shot result
		this.shotResults.push(result)
		this.uiState.shotResults = [...this.shotResults]

		// Build result text
		let resultText = ''
		let resultColor = '#ffffff'

		if (result === 'goal') {
			resultText = '¡GOL!'
			resultColor = '#22c55e'
			let bonus = ''
			if (bonuses.corner) bonus += '\n+50 Esquina'
			if (bonuses.curve) bonus += '\n+25 Curva'
			if (bonuses.streak > 1)
				bonus += `\n+${(bonuses.streak - 1) * 10} Racha x${bonuses.streak}`
			if (bonus) resultText += bonus
		} else if (result === 'save') {
			resultText = '¡Atajada!'
			resultColor = '#fbbf24'
		} else {
			resultText = '¡Fallaste!'
			resultColor = '#ef4444'
		}

		this.uiState.result = result
		this.uiState.resultText = resultText
		this.uiState.resultColor = resultColor

		this.setPhase('result')

		// Notify React
		this.callbacks.onScoreUpdate(this.state.totalScore)
		this.callbacks.onRoundComplete(this.state.round, result)

		// Next round or end game
		setTimeout(() => {
			if (this.state.round >= this.totalRounds) {
				this.endGame()
			} else {
				this.state.round++
				this.startRound()
			}
		}, TIMING.resultDisplayDuration)
	}

	private endGame() {
		this.setPhase('gameover')
		this.callbacks.onGameOver(this.state.goals, this.state.totalScore)
	}

	private screenToWorldAtZ(
		screenX: number,
		screenY: number,
		targetZ: number
	): Vector3 | null {
		const canvas = this.sceneManager.renderer.domElement
		const ndcX = (screenX / canvas.clientWidth) * 2 - 1
		const ndcY = -(screenY / canvas.clientHeight) * 2 + 1

		const camera = this.sceneManager.camera
		const near = new Vector3(ndcX, ndcY, 0).unproject(camera)
		const far = new Vector3(ndcX, ndcY, 1).unproject(camera)

		const dir = far.clone().sub(near).normalize()

		// Intersect the Z=targetZ plane
		if (Math.abs(dir.z) < 0.0001) return null
		const t = (targetZ - near.z) / dir.z
		if (t < 0) return null

		return new Vector3(near.x + dir.x * t, near.y + dir.y * t, targetZ)
	}

	private update(delta: number) {
		// Controllers not yet initialized during loading
		if (!this.ball) return

		this.input?.update(delta)
		this.ball.update(delta)
		this.goalkeeper.update(delta)
		this.plane.update(delta)
		this.clouds?.update(delta, this.sceneManager.camera)

		// Make goalkeeper billboard face camera
		this.goalkeeper.mesh.lookAt(this.sceneManager.camera.position)
	}

	dispose() {
		this.isDisposed = true
		this.input?.dispose()
		this.ball?.dispose()
		this.goalkeeper?.dispose()
		this.plane?.dispose()
		this.clouds?.dispose()
		this.fieldBuilder?.dispose()
		this.sceneManager.dispose()
	}
}
