import React, { useEffect, useRef, useState, useCallback } from 'react'
import { GameStateMachine } from './engine/GameStateMachine'
import { GamePhase, ShotResult } from './types'
import { hapticManager } from '../utils/hapticManager'

interface PenaltyGame3DCoreProps {
	onScoreUpdate: (score: number) => void
	onRoundComplete: (round: number, result: ShotResult) => void
	onGameOver: (goals: number, totalScore: number) => void
	onPhaseChange?: (phase: GamePhase) => void
	brandColor?: string
	totalRounds?: number
}

const PenaltyShootout3DCore: React.FC<PenaltyGame3DCoreProps> = ({
	onScoreUpdate,
	onRoundComplete,
	onGameOver,
	onPhaseChange,
	totalRounds = 5,
}) => {
	const containerRef = useRef<HTMLDivElement>(null)
	const gameRef = useRef<GameStateMachine | null>(null)
	const [uiState, setUiState] = useState({
		phase: 'loading' as GamePhase,
		round: 1,
		totalRounds,
		result: null as ShotResult,
		resultText: '',
		resultColor: '#ffffff',
		power: 30,
		spin: 0,
		shotResults: [] as ShotResult[],
		isDragging: false,
		loadProgress: 0,
		totalScore: 0,
	})

	const handleScoreUpdate = useCallback(
		(score: number) => {
			onScoreUpdate(score)
			hapticManager.perfectHit()
		},
		[onScoreUpdate]
	)

	const handleRoundComplete = useCallback(
		(round: number, result: ShotResult) => {
			onRoundComplete(round, result)
			if (result === 'goal') {
				hapticManager.perfectHit()
			} else {
				hapticManager.miss()
			}
		},
		[onRoundComplete]
	)

	const handleGameOver = useCallback(
		(goals: number, totalScore: number) => {
			onGameOver(goals, totalScore)
			if (goals >= Math.ceil(totalRounds / 2)) {
				hapticManager.levelUp()
			}
		},
		[onGameOver, totalRounds]
	)

	const handlePhaseChange = useCallback(
		(phase: GamePhase) => {
			onPhaseChange?.(phase)
		},
		[onPhaseChange]
	)

	useEffect(() => {
		if (!containerRef.current || gameRef.current) return

		hapticManager.init()

		const game = new GameStateMachine(
			containerRef.current,
			{
				onScoreUpdate: handleScoreUpdate,
				onRoundComplete: handleRoundComplete,
				onGameOver: handleGameOver,
				onPhaseChange: handlePhaseChange,
			},
			totalRounds
		)

		gameRef.current = game

		// Poll UI state from game engine
		const uiInterval = setInterval(() => {
			if (gameRef.current) {
				setUiState({ ...gameRef.current.uiState })
			}
		}, 50)

		return () => {
			clearInterval(uiInterval)
			if (gameRef.current) {
				gameRef.current.dispose()
				gameRef.current = null
			}
		}
	}, [
		handleScoreUpdate,
		handleRoundComplete,
		handleGameOver,
		handlePhaseChange,
		totalRounds,
	])

	const handleTap = () => {
		if (gameRef.current && uiState.phase === 'start') {
			gameRef.current.startGame()
		}
	}

	return (
		<div className="game-penalty-container" style={{ minHeight: 400 }}>
			{/* 3D Canvas Container */}
			<div
				ref={containerRef}
				className="game-penalty-canvas"
				style={{
					touchAction: 'none',
					userSelect: 'none',
					minHeight: 400,
				}}
				onClick={handleTap}
			/>

			{/* HUD Overlay */}
			<div className="game-penalty-hud">
				<div className="game-penalty-hud-bar">
					{/* Left side: Round indicator + shot dots */}
					<div className="game-penalty-hud-left">
						<span
							className="game-penalty-badge"
							style={{
								background: 'rgba(0,0,0,0.5)',
								fontFamily: 'Orbitron, sans-serif',
							}}
						>
							Tiro {uiState.round} de {uiState.totalRounds}
						</span>
						<div className="game-penalty-shot-dots">
							{Array.from({ length: uiState.totalRounds }).map((_, i) => {
								let color = '#666666'
								if (i < uiState.shotResults.length) {
									const r = uiState.shotResults[i]
									if (r === 'goal') color = '#22c55e'
									else if (r === 'save') color = '#fbbf24'
									else color = '#ef4444'
								}
								return (
									<div
										key={i}
										className="game-penalty-shot-dot"
										style={{ backgroundColor: color }}
									/>
								)
							})}
						</div>
					</div>

					{/* Right side: Score */}
					<span
						className="game-penalty-badge"
						style={{
							background: 'rgba(0,0,0,0.5)',
							fontFamily: 'Orbitron, sans-serif',
						}}
					>
						{uiState.totalScore} pts
					</span>
				</div>
			</div>

			{/* Loading overlay */}
			{uiState.phase === 'loading' && (
				<div
					className="game-penalty-loading"
					style={{ background: 'rgba(0,0,0,0.8)' }}
				>
					<div
						className="game-penalty-loading-text"
						style={{ fontFamily: 'Orbitron, sans-serif' }}
					>
						Preparando el campo...
					</div>
					<div className="game-penalty-progress-track">
						<div
							className="game-penalty-progress-fill"
							style={{
								width: `${Math.round(uiState.loadProgress * 100)}%`,
								backgroundColor: '#22c55e',
							}}
						/>
					</div>
					<div
						className="game-penalty-progress-text"
						style={{ fontFamily: 'Orbitron, sans-serif' }}
					>
						{Math.round(uiState.loadProgress * 100)}%
					</div>
				</div>
			)}

			{/* Start prompt */}
			{uiState.phase === 'start' && (
				<div className="game-penalty-prompt">
					<div
						className="game-penalty-prompt-text game-animate-pulse"
						style={{
							background: 'rgba(0,0,0,0.8)',
							fontFamily: 'Orbitron, sans-serif',
						}}
					>
						Toca para comenzar
					</div>
				</div>
			)}

			{/* Aiming instruction */}
			{uiState.phase === 'aiming' && !uiState.isDragging && (
				<div className="game-penalty-aim-hint">
					<span
						className="game-penalty-aim-text"
						style={{ background: 'rgba(0,0,0,0.5)' }}
					>
						Arrastra el balón hacia la portería
					</span>
				</div>
			)}

			{/* Power bar during aiming */}
			{uiState.phase === 'aiming' && uiState.isDragging && (
				<div
					className="game-penalty-power-bar"
					style={{ top: '30%', height: '30%' }}
				>
					<div className="game-penalty-power-track">
						<div
							className="game-penalty-power-fill"
							style={{
								height: `${((uiState.power - 30) / 70) * 100}%`,
								backgroundColor:
									uiState.power < 60
										? '#fbbf24'
										: uiState.power < 80
											? '#22c55e'
											: '#ef4444',
							}}
						/>
					</div>
				</div>
			)}

			{/* Result display */}
			{uiState.phase === 'result' && uiState.resultText && (
				<div className="game-penalty-prompt">
					<div
						className="game-penalty-result-text game-animate-bounce"
						style={{
							color: uiState.resultColor,
							background: 'rgba(0,0,0,0.7)',
							fontFamily: 'Orbitron, sans-serif',
							textShadow: '0 2px 4px rgba(0,0,0,0.5)',
						}}
					>
						{uiState.resultText}
					</div>
				</div>
			)}
		</div>
	)
}

export default PenaltyShootout3DCore
