import * as Tone from 'tone'

export class PenaltyShootoutAudioManager {
	private initialized = false
	private muted = false

	// Synthesizers
	private kickSynth: Tone.MembraneSynth | null = null
	private goalSynth: Tone.PolySynth | null = null
	private saveSynth: Tone.NoiseSynth | null = null
	private whistleSynth: Tone.Synth | null = null
	private missSynth: Tone.Synth | null = null

	async init(): Promise<void> {
		if (this.initialized) return

		await Tone.start()

		// Kick synth - powerful thump
		this.kickSynth = new Tone.MembraneSynth({
			pitchDecay: 0.02,
			octaves: 5,
			oscillator: { type: 'sine' },
			envelope: {
				attack: 0.001,
				decay: 0.3,
				sustain: 0,
				release: 0.2,
			},
			volume: -4,
		}).toDestination()

		// Goal synth - triumphant fanfare
		this.goalSynth = new Tone.PolySynth(Tone.Synth, {
			oscillator: { type: 'sawtooth' },
			envelope: {
				attack: 0.01,
				decay: 0.2,
				sustain: 0.3,
				release: 0.5,
			},
			volume: -6,
		}).toDestination()

		// Save synth - thud/noise
		this.saveSynth = new Tone.NoiseSynth({
			noise: { type: 'brown' },
			envelope: {
				attack: 0.005,
				decay: 0.2,
				sustain: 0,
				release: 0.1,
			},
			volume: -12,
		}).toDestination()

		// Whistle synth - for save/referee
		this.whistleSynth = new Tone.Synth({
			oscillator: { type: 'sine' },
			envelope: {
				attack: 0.01,
				decay: 0.1,
				sustain: 0.3,
				release: 0.2,
			},
			volume: -10,
		}).toDestination()

		// Miss synth - wobbly descending
		this.missSynth = new Tone.Synth({
			oscillator: { type: 'triangle' },
			envelope: {
				attack: 0.01,
				decay: 0.3,
				sustain: 0,
				release: 0.3,
			},
			volume: -8,
		}).toDestination()

		this.initialized = true
	}

	// Powerful kick thump
	playKick(): void {
		if (!this.initialized || this.muted || !this.kickSynth) return
		const now = Tone.now()
		this.kickSynth.triggerAttackRelease('C2', '8n', now)
	}

	// Triumphant goal fanfare
	playGoal(): void {
		if (!this.initialized || this.muted || !this.goalSynth) return
		const now = Tone.now()

		// Triumphant chord progression
		const fanfare = [
			{ notes: ['C4', 'E4', 'G4'], time: 0 },
			{ notes: ['D4', 'F4', 'A4'], time: 0.15 },
			{ notes: ['E4', 'G4', 'B4'], time: 0.3 },
			{ notes: ['C5', 'E5', 'G5'], time: 0.5 },
		]

		fanfare.forEach(({ notes, time }) => {
			this.goalSynth!.triggerAttackRelease(notes, '4n', now + time)
		})
	}

	// Save - thud + whistle
	playSave(): void {
		if (!this.initialized || this.muted) return
		const now = Tone.now()

		// Thud
		if (this.saveSynth) {
			this.saveSynth.triggerAttackRelease('8n', now)
		}

		// Short whistle
		if (this.whistleSynth) {
			this.whistleSynth.triggerAttackRelease('E6', '16n', now + 0.15)
			this.whistleSynth.triggerAttackRelease('C6', '8n', now + 0.25)
		}
	}

	// Miss - wobbly descending tone
	playMiss(): void {
		if (!this.initialized || this.muted || !this.missSynth) return
		const now = Tone.now()

		// Descending wobbly notes
		const notes = ['E4', 'D4', 'C4', 'B3']
		notes.forEach((note, i) => {
			this.missSynth!.triggerAttackRelease(note, '16n', now + i * 0.12)
		})
	}

	setMuted(muted: boolean): void {
		this.muted = muted
	}

	isMuted(): boolean {
		return this.muted
	}

	dispose(): void {
		if (!this.initialized) return

		this.kickSynth?.dispose()
		this.goalSynth?.dispose()
		this.saveSynth?.dispose()
		this.whistleSynth?.dispose()
		this.missSynth?.dispose()

		this.kickSynth = null
		this.goalSynth = null
		this.saveSynth = null
		this.whistleSynth = null
		this.missSynth = null

		this.initialized = false
	}
}

export const penaltyShootoutAudio = new PenaltyShootoutAudioManager()
