import {
	Texture,
	TextureLoader,
	LoadingManager,
	RepeatWrapping,
	SRGBColorSpace,
} from 'three'
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader.js'
import type { GLTF } from 'three/examples/jsm/loaders/GLTFLoader.js'

const BASE_PATH = '/games/penalty-shootout'

export interface PreloadedAssets {
	ballGLB: GLTF | null
	goalGLB: GLTF | null
	planeGLB: GLTF | null
	grassTexture: Texture | null
	staticAdTexture: Texture | null
	goalkeeperTexture: Texture | null
	planeTexture: Texture | null
	flyingAdTexture: Texture | null
	particlesTexture: Texture | null
}

export class AssetPreloader {
	async load(
		onProgress?: (loaded: number, total: number) => void
	): Promise<PreloadedAssets> {
		const total = 9
		let loaded = 0

		const assets: PreloadedAssets = {
			ballGLB: null,
			goalGLB: null,
			planeGLB: null,
			grassTexture: null,
			staticAdTexture: null,
			goalkeeperTexture: null,
			planeTexture: null,
			flyingAdTexture: null,
			particlesTexture: null,
		}

		const track = <T>(promise: Promise<T>): Promise<T | null> =>
			promise
				.then(result => {
					loaded++
					onProgress?.(loaded, total)
					return result
				})
				.catch(() => {
					loaded++
					onProgress?.(loaded, total)
					return null
				})

		const textureLoader = new TextureLoader()

		const loadTexture = (path: string): Promise<Texture> =>
			new Promise((resolve, reject) => {
				textureLoader.load(`${BASE_PATH}/${path}`, resolve, undefined, reject)
			})

		const loadGLTF = (
			path: string,
			manager?: LoadingManager
		): Promise<GLTF> => {
			const loader = new GLTFLoader(manager)
			return new Promise((resolve, reject) => {
				loader.load(`${BASE_PATH}/${path}`, resolve, undefined, reject)
			})
		}

		// Plane GLB needs a custom LoadingManager to redirect blob textures
		const planeManager = new LoadingManager()
		planeManager.setURLModifier((url: string) => {
			if (url.startsWith('blob:')) {
				return `${BASE_PATH}/plane_texture.png`
			}
			return url
		})

		const [
			ballGLB,
			goalGLB,
			planeGLB,
			grassTexture,
			staticAdTexture,
			goalkeeperTexture,
			planeTexture,
			flyingAdTexture,
			particlesTexture,
		] = await Promise.all([
			track(loadGLTF('ball.glb')),
			track(loadGLTF('goal.glb')),
			track(loadGLTF('plane.glb', planeManager)),
			track(loadTexture('grass.webp')),
			track(loadTexture('static-ad.png')),
			track(loadTexture('goalkeeper.webp')),
			track(loadTexture('plane_texture.png')),
			track(loadTexture('flying-ad.png')),
			track(loadTexture('particles.webp')),
		])

		assets.ballGLB = ballGLB
		assets.goalGLB = goalGLB
		assets.planeGLB = planeGLB
		assets.grassTexture = grassTexture
		assets.staticAdTexture = staticAdTexture
		assets.goalkeeperTexture = goalkeeperTexture
		assets.planeTexture = planeTexture
		assets.flyingAdTexture = flyingAdTexture
		assets.particlesTexture = particlesTexture

		// Pre-configure grass texture wrapping
		if (assets.grassTexture) {
			assets.grassTexture.wrapS = RepeatWrapping
			assets.grassTexture.wrapT = RepeatWrapping
		}

		// Pre-configure goalkeeper texture
		if (assets.goalkeeperTexture) {
			assets.goalkeeperTexture.colorSpace = SRGBColorSpace
		}

		return assets
	}
}
