import { INPUT, SPIN_PHYSICS } from '../constants'

interface PointerPoint {
	x: number
	y: number
	time: number
}

export interface ShotInput {
	directionX: number // -1 to 1 (left to right)
	power: number // 30 to 100
	angularVelocity: number // raw accumulated angular velocity at release
	isCharged: boolean // whether ball was charged at release
}

type DragUpdateCallback = (
	dx: number,
	dy: number,
	angularVelocity: number,
	isCharged: boolean,
	power: number
) => void

export class InputManager {
	private container: HTMLElement
	private isDragging: boolean = false
	private dragStartPos: { x: number; y: number } | null = null
	private pointerHistory: PointerPoint[] = [] // kept for speed/velocity calculations
	private currentPower: number = 30

	// Torque-based spin state
	private angularVelocity: number = 0
	private isCharged: boolean = false
	private lastPointerPos: { x: number; y: number } | null = null
	private spinCenter: { x: number; y: number } | null = null
	private lastMoveTime: number = 0
	private chargeGraceTimer: number = 0

	// Ball visual position for drag feedback
	public ballScreenX: number = 0
	public ballScreenY: number = 0

	private onShotCallback: ((input: ShotInput) => void) | null = null
	private onDragUpdateCallback: DragUpdateCallback | null = null
	private onDragStartCallback: (() => void) | null = null
	private onDragEndCallback: ((firedShot: boolean) => void) | null = null

	// Ball screen position (set by game)
	private ballCenterX: number = 0
	private ballCenterY: number = 0
	private ballRadius: number = 40

	constructor(container: HTMLElement) {
		this.container = container
		this.handlePointerDown = this.handlePointerDown.bind(this)
		this.handlePointerMove = this.handlePointerMove.bind(this)
		this.handlePointerUp = this.handlePointerUp.bind(this)
	}

	enable() {
		this.container.addEventListener('pointerdown', this.handlePointerDown)
		this.container.addEventListener('pointermove', this.handlePointerMove)
		this.container.addEventListener('pointerup', this.handlePointerUp)
		this.container.addEventListener('pointercancel', this.handlePointerUp)
	}

	disable() {
		this.container.removeEventListener('pointerdown', this.handlePointerDown)
		this.container.removeEventListener('pointermove', this.handlePointerMove)
		this.container.removeEventListener('pointerup', this.handlePointerUp)
		this.container.removeEventListener('pointercancel', this.handlePointerUp)
		this.isDragging = false
	}

	setBallPosition(screenX: number, screenY: number, radius: number) {
		this.ballCenterX = screenX
		this.ballCenterY = screenY
		this.ballRadius = radius
		this.ballScreenX = screenX
		this.ballScreenY = screenY
	}

	onShot(callback: (input: ShotInput) => void) {
		this.onShotCallback = callback
	}

	onDragUpdate(callback: DragUpdateCallback) {
		this.onDragUpdateCallback = callback
	}

	onDragStart(callback: () => void) {
		this.onDragStartCallback = callback
	}

	onDragEnd(callback: (firedShot: boolean) => void) {
		this.onDragEndCallback = callback
	}

	private getPointerPos(e: PointerEvent): { x: number; y: number } {
		const rect = this.container.getBoundingClientRect()
		return {
			x: e.clientX - rect.left,
			y: e.clientY - rect.top,
		}
	}

	private handlePointerDown(e: PointerEvent) {
		const pos = this.getPointerPos(e)

		// Must touch near the ball
		const distToBall = Math.sqrt(
			Math.pow(pos.x - this.ballCenterX, 2) +
				Math.pow(pos.y - this.ballCenterY, 2)
		)

		if (distToBall < this.ballRadius + 40) {
			this.isDragging = true
			this.dragStartPos = { x: this.ballCenterX, y: this.ballCenterY }
			this.ballScreenX = pos.x
			this.ballScreenY = pos.y
			this.pointerHistory = [{ x: pos.x, y: pos.y, time: Date.now() }]
			this.angularVelocity = 0
			this.isCharged = false
			this.chargeGraceTimer = 0
			this.lastPointerPos = { x: pos.x, y: pos.y }
			this.spinCenter = { x: pos.x, y: pos.y }
			this.lastMoveTime = Date.now()
			this.currentPower = 30
			this.onDragStartCallback?.()
		}
	}

	private handlePointerMove(e: PointerEvent) {
		if (!this.isDragging || !this.dragStartPos) return

		const pos = this.getPointerPos(e)
		const now = Date.now()

		// Calculate drag position — set directly (3D lerp provides visible drag)
		let targetX = pos.x
		let targetY = pos.y

		// Constrain drag distance
		const dx = targetX - this.dragStartPos.x
		const dy = targetY - this.dragStartPos.y
		const dist = Math.sqrt(dx * dx + dy * dy)

		if (dist > INPUT.maxDragDistance) {
			const ratio = INPUT.maxDragDistance / dist
			targetX = this.dragStartPos.x + dx * ratio
			targetY = this.dragStartPos.y + dy * ratio
		}

		// Set ball position directly — the 3D DRAG.followSpeed lerp provides subtle drag
		this.ballScreenX = targetX
		this.ballScreenY = targetY

		// --- Torque-based spin accumulation (ref: Thrower.cs AddTorque) ---
		// spinCenter follows pointer with lag (mimics reference ball-follows-pointer)
		if (this.spinCenter) {
			const now2 = Date.now()
			const dt = Math.min(
				0.05,
				Math.max(0.001, (now2 - this.lastMoveTime) / 1000)
			)
			this.lastMoveTime = now2
			const followSpeed = 10 // matches reference Thrower.cs _followSpeed
			const lerpFactor = Math.min(1, followSpeed * dt)
			this.spinCenter.x += (pos.x - this.spinCenter.x) * lerpFactor
			this.spinCenter.y += (pos.y - this.spinCenter.y) * lerpFactor
		}

		if (this.lastPointerPos) {
			// Pointer movement direction
			const moveDx = pos.x - this.lastPointerPos.x
			const moveDy = pos.y - this.lastPointerPos.y
			const moveLen = Math.sqrt(moveDx * moveDx + moveDy * moveDy)

			if (moveLen > 1) {
				const normMoveDx = moveDx / moveLen
				const normMoveDy = moveDy / moveLen

				// Direction from pointer to lagging spin center
				const toBallDx = this.spinCenter!.x - pos.x
				const toBallDy = this.spinCenter!.y - pos.y
				const toBallLen = Math.sqrt(toBallDx * toBallDx + toBallDy * toBallDy)

				if (toBallLen > SPIN_PHYSICS.minCircleRadius) {
					const normToBallDx = toBallDx / toBallLen
					const normToBallDy = toBallDy / toBallLen

					// 2D cross product = circular motion detection
					const cross = normToBallDx * normMoveDy - normToBallDy * normMoveDx

					// Apply torque (negated to match reference convention)
					this.angularVelocity += cross * SPIN_PHYSICS.torqueMultiplier * -1
				}
			}
		}

		this.lastPointerPos = { x: pos.x, y: pos.y }

		// Track pointer history for speed/velocity calculations
		this.pointerHistory.push({ x: pos.x, y: pos.y, time: now })
		// Keep last 500ms of history for speed calculations
		this.pointerHistory = this.pointerHistory.filter(p => now - p.time < 500)

		// Calculate instantaneous speed for power
		const speed = this.calculateSpeed()
		this.currentPower = Math.min(100, Math.max(30, speed / INPUT.powerScale))
	}

	update(delta: number) {
		if (!this.isDragging) return

		// Continuous angular drag — frame-rate independent
		this.angularVelocity *= Math.pow(1 - SPIN_PHYSICS.angularDrag, delta * 60)

		// Clamp
		this.angularVelocity = Math.max(
			-SPIN_PHYSICS.maxAngularVelocity,
			Math.min(SPIN_PHYSICS.maxAngularVelocity, this.angularVelocity)
		)

		// Charge/discharge hysteresis with grace period
		const absAngVel = Math.abs(this.angularVelocity)
		if (!this.isCharged && absAngVel > SPIN_PHYSICS.chargeThreshold) {
			this.isCharged = true
			this.chargeGraceTimer = 0
		}
		if (this.isCharged && absAngVel < SPIN_PHYSICS.dischargeThreshold) {
			this.chargeGraceTimer += delta
			if (this.chargeGraceTimer > SPIN_PHYSICS.chargeGracePeriod) {
				this.isCharged = false
			}
		} else if (this.isCharged) {
			this.chargeGraceTimer = 0
		}

		// Fire callback every frame so 3D visuals stay in sync even when pointer is still
		if (this.onDragUpdateCallback && this.dragStartPos) {
			this.onDragUpdateCallback(
				this.ballScreenX - this.dragStartPos.x,
				this.ballScreenY - this.dragStartPos.y,
				this.angularVelocity,
				this.isCharged,
				this.currentPower
			)
		}
	}

	private handlePointerUp(_e: PointerEvent) {
		if (!this.isDragging || !this.dragStartPos) return

		this.isDragging = false

		// Calculate release velocity
		const velocity = this.calculateReleaseVelocity()

		let firedShot = false

		// Check if ball was released with upward momentum
		if (
			velocity.y < -INPUT.minReleaseSpeed &&
			this.pointerHistory.length >= 3
		) {
			firedShot = true
			const power = Math.min(
				100,
				Math.max(30, velocity.speed / INPUT.powerScale)
			)

			// Velocity-based direction: use release flick angle
			const velRatio = velocity.y !== 0 ? velocity.x / Math.abs(velocity.y) : 0
			const directionX = velRatio * 1.5 // scale so ~34° angle = edge of goal
			const clampedDirection = Math.max(-1, Math.min(1, directionX))

			if (this.onShotCallback) {
				this.onShotCallback({
					directionX: clampedDirection,
					power,
					angularVelocity: this.angularVelocity,
					isCharged: this.isCharged,
				})
			}
		}

		this.onDragEndCallback?.(firedShot)

		// Reset
		this.pointerHistory = []
		this.angularVelocity = 0
		this.isCharged = false
		this.lastPointerPos = null
		this.spinCenter = null
		this.lastMoveTime = 0
		this.ballScreenX = this.ballCenterX
		this.ballScreenY = this.ballCenterY
	}

	private calculateSpeed(): number {
		if (this.pointerHistory.length < 3) return 0

		const recent = this.pointerHistory.slice(-3)
		const first = recent[0]
		const last = recent[recent.length - 1]
		const dt = (last.time - first.time) / 1000

		if (dt <= 0) return 0

		const dx = last.x - first.x
		const dy = last.y - first.y
		return Math.sqrt(dx * dx + dy * dy) / dt
	}

	private calculateReleaseVelocity(): {
		x: number
		y: number
		speed: number
	} {
		if (this.pointerHistory.length < 2) {
			return { x: 0, y: 0, speed: 0 }
		}

		const recent = this.pointerHistory.slice(-5)
		if (recent.length < 2) return { x: 0, y: 0, speed: 0 }

		const first = recent[0]
		const last = recent[recent.length - 1]
		const dt = (last.time - first.time) / 1000

		if (dt <= 0) return { x: 0, y: 0, speed: 0 }

		const vx = (last.x - first.x) / dt
		const vy = (last.y - first.y) / dt
		const speed = Math.sqrt(vx * vx + vy * vy)

		return { x: vx, y: vy, speed }
	}

	dispose() {
		this.disable()
		this.onShotCallback = null
		this.onDragUpdateCallback = null
		this.onDragStartCallback = null
		this.onDragEndCallback = null
	}
}
