import { Vector3 } from 'three'
import { BALL_3D, SPIN_PHYSICS } from '../constants'

export interface TrajectoryParams {
	start: Vector3
	target: Vector3 // target.x already includes charged endpoint shift
	angularVelocity: number // raw angular velocity
	power: number // 30 to 100
}

/**
 * Calculate ball position along 3D trajectory at time t (0 to 1)
 * Uses quadratic Bezier for X (spin curves via control point),
 * parabolic arc for Y, linear for Z.
 */
export function getTrajectoryPosition(
	params: TrajectoryParams,
	t: number
): Vector3 {
	const { start, target, angularVelocity, power } = params

	// Normalize angular velocity to -1..1
	const normalizedSpin = Math.max(
		-1,
		Math.min(1, angularVelocity / SPIN_PHYSICS.maxAngularVelocity)
	)

	// Quadratic Bezier for X — spin curves the path via the control point
	// Endpoint already includes charged shift (computed by caller)
	const midX = (start.x + target.x) / 2
	const controlX = midX - normalizedSpin * SPIN_PHYSICS.curveControlShift
	const endX = target.x
	const omt = 1 - t
	const x = omt * omt * start.x + 2 * omt * t * controlX + t * t * endX

	// Parabolic arc height
	const peakHeight = 0.5 + (power / 100) * 2.0 // Higher with more power
	const arcY = peakHeight * 4 * t * (1 - t) // Peaks at t=0.5
	const y = Math.max(BALL_3D.radius, lerp(start.y, target.y, t) + arcY)
	const z = lerp(start.z, target.z, t)

	return new Vector3(x, y, z)
}

/**
 * Calculate ball rotation at time t
 * Returns { x: forward roll, y: side spin }
 */
export function getTrajectoryRotation(
	angularVelocity: number,
	t: number
): { x: number; y: number } {
	// Forward roll: 540 degrees over flight
	const forwardRoll = t * Math.PI * 3

	// Side spin proportional to angular velocity (normalized)
	const normalizedSpin = Math.max(
		-1,
		Math.min(1, angularVelocity / SPIN_PHYSICS.maxAngularVelocity)
	)
	const sideSpin = normalizedSpin * t * Math.PI * 2

	return { x: forwardRoll, y: sideSpin }
}

/**
 * Map screen-space drag to 3D goal target position
 */
export function screenDragToGoalTarget(
	dragX: number, // normalized -1 to 1
	power: number, // 30 to 100
	goalWidth: number,
	goalHeight: number
): { x: number; y: number } {
	// X: map drag direction to goal width
	const targetX = dragX * (goalWidth / 2) * 0.9 // 90% to avoid exact posts

	// Y: power determines height
	let targetY: number
	if (power < 55) {
		// Low shot
		targetY = goalHeight * 0.2
	} else if (power < 80) {
		// Mid shot
		targetY = goalHeight * 0.5
	} else {
		// High shot
		targetY = goalHeight * 0.8
	}

	return { x: targetX, y: targetY }
}

function lerp(a: number, b: number, t: number): number {
	return a + (b - a) * t
}
