import {
	Scene,
	Mesh,
	PlaneGeometry,
	MeshBasicMaterial,
	LinearFilter,
	Vector3,
	Texture,
} from 'three'
import { GOALKEEPER_3D, GOAL_3D, SPIN_PHYSICS } from '../constants'
import { GoalkeeperDifficulty } from '../types'

type DiveDirection = 'left' | 'right' | 'center'

export class GoalkeeperController {
	public mesh: Mesh
	private scene: Scene

	// Dive animation state
	private isDiving: boolean = false
	private diveStartX: number = 0
	private diveTargetX: number = 0
	private diveProgress: number = 0
	private diveDuration: number = GOALKEEPER_3D.diveDuration

	// Spritesheet state
	private frameWidth: number = 128
	private totalFrames: number = 6
	private currentFrame: number = 0

	constructor(scene: Scene, preloadedTexture?: Texture | null) {
		this.scene = scene

		const geometry = new PlaneGeometry(
			GOALKEEPER_3D.width,
			GOALKEEPER_3D.height
		)

		let material: MeshBasicMaterial

		if (preloadedTexture) {
			// Configure spritesheet settings on the pre-loaded texture
			preloadedTexture.magFilter = LinearFilter
			preloadedTexture.minFilter = LinearFilter
			preloadedTexture.generateMipmaps = false
			// colorSpace already set in preloader
			preloadedTexture.repeat.set(1 / this.totalFrames, 1)
			preloadedTexture.offset.set(0, 0)

			material = new MeshBasicMaterial({
				map: preloadedTexture,
				transparent: true,
				alphaTest: 0.1,
			})
		} else {
			// No texture — invisible placeholder
			material = new MeshBasicMaterial({
				transparent: true,
				opacity: 0,
			})
		}

		this.mesh = new Mesh(geometry, material)
		this.mesh.position.set(
			GOALKEEPER_3D.startPosition.x,
			GOALKEEPER_3D.startPosition.y,
			GOALKEEPER_3D.startPosition.z
		)
		scene.add(this.mesh)
	}

	private setFrame(frame: number) {
		this.currentFrame = frame
		const material = this.mesh.material as MeshBasicMaterial
		if (material.map) {
			material.map.offset.x = frame / this.totalFrames
		}
	}

	decideDive(
		targetX: number,
		angularVelocity: number,
		difficulty: GoalkeeperDifficulty
	): DiveDirection {
		const threshold = GOAL_3D.width / 4

		let finalDirection: DiveDirection
		if (targetX < -threshold) {
			finalDirection = 'left'
		} else if (targetX > threshold) {
			finalDirection = 'right'
		} else {
			finalDirection = 'center'
		}

		// Curve can fool the goalkeeper — normalize angVel internally
		const normalizedAngVel = Math.min(
			1,
			Math.abs(angularVelocity) / SPIN_PHYSICS.maxAngularVelocity
		)
		const curveFoolChance = normalizedAngVel * 0.3

		if (Math.random() < difficulty.correctDiveChance - curveFoolChance) {
			return finalDirection
		} else {
			const directions: DiveDirection[] = ['left', 'right', 'center']
			const wrongDirections = directions.filter(d => d !== finalDirection)
			return wrongDirections[Math.floor(Math.random() * wrongDirections.length)]
		}
	}

	dive(direction: DiveDirection) {
		this.isDiving = true
		this.diveStartX = this.mesh.position.x
		this.diveProgress = 0

		if (direction === 'left') {
			this.diveTargetX =
				GOALKEEPER_3D.startPosition.x - GOALKEEPER_3D.diveDistance
			this.mesh.scale.x = -1 // Flip for left dive
			this.setFrame(1) // Start dive animation
		} else if (direction === 'right') {
			this.diveTargetX =
				GOALKEEPER_3D.startPosition.x + GOALKEEPER_3D.diveDistance
			this.mesh.scale.x = 1
			this.setFrame(1)
		} else {
			this.diveTargetX = GOALKEEPER_3D.startPosition.x
			this.mesh.scale.x = 1
			this.setFrame(5) // Crouch frame
		}
	}

	checkSave(
		ballPosition: Vector3,
		diveDirection: DiveDirection,
		difficulty: GoalkeeperDifficulty,
		power: number,
		curveAmount: number
	): boolean {
		// Only check if goalkeeper dove in correct direction
		const threshold = GOAL_3D.width / 4
		let shotDirection: DiveDirection
		if (ballPosition.x < -threshold) {
			shotDirection = 'left'
		} else if (ballPosition.x > threshold) {
			shotDirection = 'right'
		} else {
			shotDirection = 'center'
		}

		if (diveDirection !== shotDirection) {
			return false // Wrong direction = no save
		}

		// Calculate effective coverage
		const gkX = this.diveTargetX
		const distance = Math.abs(ballPosition.x - gkX)
		const baseCoverage = GOALKEEPER_3D.width * (1 + difficulty.saveCoverage)

		// Power reduces coverage
		const powerFactor = Math.max(0.5, 1 - (power - 50) / 100)
		// Curve reduces coverage
		const curveFactor = 1.2 - curveAmount * 0.6
		// Top corners harder to save
		const isTopCorner =
			ballPosition.y > GOAL_3D.height * 0.6 &&
			Math.abs(ballPosition.x) > GOAL_3D.width / 3
		const cornerFactor = isTopCorner ? 0.5 : 1.0

		const effectiveCoverage =
			baseCoverage * powerFactor * curveFactor * cornerFactor

		return distance < effectiveCoverage
	}

	update(delta: number) {
		if (!this.isDiving) return

		this.diveProgress += (delta * 1000) / this.diveDuration

		if (this.diveProgress >= 1) {
			this.diveProgress = 1
			this.isDiving = false
			// Set to final dive frame
			if (this.diveTargetX !== GOALKEEPER_3D.startPosition.x) {
				this.setFrame(3) // Final dive frame
			}
		}

		// Ease-out position interpolation
		const eased = 1 - Math.pow(1 - this.diveProgress, 2)
		this.mesh.position.x =
			this.diveStartX + (this.diveTargetX - this.diveStartX) * eased

		// Animate through dive frames
		if (this.diveTargetX !== GOALKEEPER_3D.startPosition.x) {
			if (this.diveProgress < 0.3) {
				this.setFrame(1)
			} else if (this.diveProgress < 0.6) {
				this.setFrame(2)
			} else {
				this.setFrame(3)
			}
		}
	}

	snapToSave(ballX: number, ballY: number) {
		this.mesh.position.x = ballX
		this.mesh.position.y = Math.max(GOALKEEPER_3D.startPosition.y, ballY)
		this.isDiving = false
		this.diveProgress = 1
		// Set final dive frame
		if (this.diveTargetX !== GOALKEEPER_3D.startPosition.x) {
			this.setFrame(3)
		}
	}

	reset() {
		this.mesh.position.set(
			GOALKEEPER_3D.startPosition.x,
			GOALKEEPER_3D.startPosition.y,
			GOALKEEPER_3D.startPosition.z
		)
		this.mesh.scale.x = 1
		this.isDiving = false
		this.diveProgress = 0
		this.setFrame(0) // Idle
	}

	dispose() {
		this.mesh.geometry.dispose()
		const material = this.mesh.material as MeshBasicMaterial
		if (material.map) material.map.dispose()
		material.dispose()
		this.scene.remove(this.mesh)
	}
}
